import { Flashcard } from './ib-flashcard-data';
export const AM_FLASHCARDS: Flashcard[] = [
  // FOUNDATIONS (20)
  { q: "What is asset management?", a: "Professional management of capital to achieve specific return and risk outcomes over a defined time horizon for clients/institutions.", category: "Foundations",difficulty:"Intermediate"},
  { q: "Good business vs good investment?", a: "A great business can be poor if overpriced. A mediocre business can be good if expectations are too low. Price vs value.", category: "Foundations",difficulty:"Intermediate"},
  { q: "What is variant perception?", a: "A view that is both different from consensus and correct often enough to matter. The source of alpha.", category: "Foundations",difficulty:"Intermediate"},
  { q: "How does AM differ from banking?", a: "AM: disciplined capital allocation, portfolio construction, benchmark-relative performance. Banking: transactions, advisory, capital raising.", category: "Foundations",difficulty:"Intermediate"},
  { q: "How does AM differ from hedge funds?", a: "AM: usually benchmark-aware, longer horizon, constrained mandates. HF: more flexible, shorter horizon, leverage, absolute return.", category: "Foundations",difficulty:"Intermediate"},
  { q: "What are sources of edge?", a: "Superior analysis, better industry knowledge, longer horizon, behavioral discipline, better portfolio construction, better risk management.", category: "Foundations",difficulty:"Intermediate"},
  { q: "What is process over prediction?", a: "Consistently good process matters more than pretending to forecast every data point. Discipline beats brilliance.", category: "Foundations",difficulty:"Intermediate"},
  { q: "What is the institutional investment process?", a: "Universe → idea gen → research → valuation → risk analysis → portfolio fit → decision → monitoring → exit discipline.", category: "Foundations",difficulty:"Intermediate"},
  { q: "Active vs passive investing?", a: "Active aims to outperform through selection/timing. Passive replicates an index. Active requires edge to justify fees.", category: "Foundations",difficulty:"Intermediate"},
  { q: "What are the core investor questions?", a: "1) What is it worth? 2) What is priced in? 3) Why is market wrong? 4) Catalyst? 5) Key risks? 6) Portfolio fit?", category: "Foundations",difficulty:"Intermediate"},
  // MARKETS & ASSET CLASSES (25)
  { q: "What drives equity returns?", a: "Earnings growth, multiple expansion/contraction, dividends/buybacks, balance sheet changes, discount rate shifts.", category: "Markets",difficulty:"Advanced"},
  { q: "What drives bond prices?", a: "Interest rates, inflation expectations, credit spreads, duration, convexity, default risk, liquidity.", category: "Markets",difficulty:"Advanced"},
  { q: "Why do discount rates matter?", a: "Every asset's price depends on discounting future cash flows. Rising rates hurt long-duration assets most.", category: "Markets",difficulty:"Intermediate"},
  { q: "What is a benchmark?", a: "Reference portfolio for measuring active performance. Shapes sector weights, tracking error, risk budget.", category: "Markets",difficulty:"Intermediate"},
  { q: "What is market efficiency?", a: "Prices reflect information quickly. Active opportunities come from behavioral biases, complexity, forced flows, horizon differences.", category: "Markets",difficulty:"Intermediate"},
  { q: "What role does cash play in portfolios?", a: "Liquidity reserve, tactical allocation, benchmark-relative choice, optionality in volatile markets. Holding cash is an active decision.", category: "Markets",difficulty:"Intermediate"},
  { q: "How do higher rates affect equities?", a: "Increase discount rates → lower PV of cash flows. Compress multiples. Hurt long-duration/growth stocks most.", category: "Markets",difficulty:"Intermediate"},
  { q: "What is credit spread?", a: "Yield premium over risk-free rate compensating for default risk, liquidity, etc. Widening signals stress.", category: "Markets",difficulty:"Intermediate"},
  { q: "What is duration?", a: "Measure of interest rate sensitivity. Longer duration = more price sensitivity to rate changes.", category: "Markets",difficulty:"Advanced"},
  { q: "Why does a stock rise?", a: "Not because earnings are good absolutely - because outcomes are better than what was priced in, or multiples expand.", category: "Markets",difficulty:"Intermediate"},
  // FUNDAMENTAL ANALYSIS (30)
  { q: "How do you analyze a business model?", a: "What does it sell? Who pays? Why? What drives volume/price/mix? Major costs? What's defensible or vulnerable?", category: "Analysis",difficulty:"Intermediate"},
  { q: "What are revenue drivers?", a: "Units × price, customers × spend, subscribers × ARPU, transactions × take rate, assets × fee rate.", category: "Analysis",difficulty:"Intermediate"},
  { q: "Why do margins matter?", a: "Reveal pricing power, scale benefits, input sensitivity, operating leverage, quality of growth.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What is ROIC?", a: "Return on Invested Capital. Growth only creates value if ROIC > cost of capital.", category: "Analysis",difficulty:"Intermediate"},
  { q: "Why do returns on capital matter?", a: "High-ROIC businesses compound value faster when reinvesting. Growth without returns destroys value.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What is free cash flow conversion?", a: "How much of earnings turns into cash. Weak conversion (rising AR, heavy CapEx) is a red flag.", category: "Analysis",difficulty:"Intermediate"},
  { q: "Why does balance sheet matter?", a: "A great business model can still create bad investment if leverage, liquidity, or refinancing risk is severe.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What is operating leverage?", a: "High fixed costs: revenue growth drives disproportionate profit growth (or decline). Amplifies both up and down.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What are red flags in analysis?", a: "Revenue growth with deteriorating cash flow, repeated one-time adjustments, weak balance sheet hidden by adjusted metrics, opaque disclosures.", category: "Analysis",difficulty:"Intermediate"},
  { q: "How do you evaluate management?", a: "Capital allocation track record, incentive alignment, M&A discipline, buyback timing, operational execution, candor.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What is competitive advantage?", a: "Sustainable edge: brand, scale, network effects, switching costs, IP, regulatory barriers, cost leadership.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What is industry structure?", a: "Rivalry, entry barriers, substitutes, buyer/supplier power. Great teams can struggle in structurally poor industries.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What is pricing power?", a: "Ability to raise prices without losing customers. Sign of competitive strength and margin durability.", category: "Analysis",difficulty:"Intermediate"},
  { q: "Recurring vs transactional revenue?", a: "Recurring (subscriptions, contracts) is more predictable and valuable. Transactional is lumpier and less certain.", category: "Analysis",difficulty:"Intermediate"},
  { q: "What is asset-light vs capital-intensive?", a: "Asset-light: low CapEx, high returns (software). Capital-intensive: heavy CapEx, assets drive revenue (manufacturing).", category: "Analysis",difficulty:"Intermediate"},
  // VALUATION (25)
  { q: "What is intrinsic vs relative value?", a: "Intrinsic = DCF-based worth from cash flows. Relative = comparison to peer multiples. Triangulate both.", category: "Valuation",difficulty:"Intermediate"},
  { q: "What is margin of safety?", a: "Buying with enough cushion that even if assumptions are wrong, downside is limited vs upside.", category: "Valuation",difficulty:"Intermediate"},
  { q: "Common valuation methods?", a: "DCF, trading comps, sum-of-parts, DDM, NAV, replacement cost, depending on business type.", category: "Valuation",difficulty:"Intermediate"},
  { q: "How do AM professionals use DCF?", a: "Less for precision, more to understand what assumptions are embedded in price and whether differentiated view matters.", category: "Valuation",difficulty:"Advanced"},
  { q: "What is FCF yield?", a: "Free Cash Flow / Market Cap (or EV). Measures cash return on price paid. Higher = cheaper.", category: "Valuation",difficulty:"Intermediate"},
  { q: "Why can cheap stocks be dangerous?", a: "Value traps: deteriorating industry, leverage, governance, no catalyst, earnings collapse. Cheap isn't enough.", category: "Valuation",difficulty:"Intermediate"},
  { q: "How do you reverse-engineer expectations?", a: "What growth, margin, ROIC does current multiple imply? Is reality likely better or worse than implied?", category: "Valuation",difficulty:"Intermediate"},
  { q: "What is EV/EBITDA?", a: "Enterprise Value / EBITDA. Capital-structure neutral, widely used for comparing companies.", category: "Valuation",difficulty:"Intermediate"},
  { q: "Why can P/E be misleading?", a: "Affected by capital structure, non-operating items, tax differences, accounting distortions.", category: "Valuation",difficulty:"Intermediate"},
  { q: "How do you value a bank?", a: "P/Book, P/E, ROTCE-based. Traditional DCF/EV-EBITDA less useful since debt is operational.", category: "Valuation",difficulty:"Intermediate"},
  { q: "How do you value a REIT?", a: "FFO/AFFO multiples, cap rates, NAV. Depreciation overstates expense for real estate.", category: "Valuation",difficulty:"Intermediate"},
  { q: "What is growth-duration sensitivity?", a: "High-growth = long-duration asset. More value in distant future → more sensitive to discount rate changes.", category: "Valuation",difficulty:"Advanced"},
  // PORTFOLIO CONSTRUCTION (20)
  { q: "Why does portfolio construction matter?", a: "Can be right on ideas but underperform due to poor sizing, concentration, factor exposure, or benchmark mismatch.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "How would you size a position?", a: "Conviction, downside risk, balance sheet, correlation with holdings, liquidity, benchmark context, catalyst visibility.", category: "Portfolio",difficulty:"Advanced"},
  { q: "What is true diversification?", a: "Not just many names - diversity across sectors, factors, business models, geographies, durations.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "Concentrated vs diversified?", a: "Concentrated: more upside if right, more downside if wrong. Diversified: lower idiosyncratic risk. Right level depends on edge and mandate.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "What is tracking error?", a: "Volatility of excess return vs benchmark. Measures how much active risk.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "What is active share?", a: "How different portfolio is from benchmark by holdings. Higher = more differentiated.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "What types of risk exist?", a: "Business, valuation, balance sheet, liquidity, factor, macro, currency, duration, regulatory, thesis, behavioral risk.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "Is volatility = risk?", a: "Volatility is a proxy but true risk = permanent capital impairment, forced selling, inability to meet liabilities.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "What is sell discipline?", a: "Thesis broken, price ≥ fair value, better opportunity, risk-reward deteriorated, portfolio needs rebalance.", category: "Portfolio",difficulty:"Intermediate"},
  { q: "What is capacity?", a: "How much capital a strategy absorbs before edge deteriorates. $10M idea may fail at $10B.", category: "Portfolio",difficulty:"Intermediate"},
  // STOCK PITCH (15)
  { q: "Walk me through a stock pitch.", a: "1) Recommendation, 2) Business overview, 3) Why market is wrong, 4) Valuation, 5) Catalysts, 6) Risks.", category: "Stock Pitch",difficulty:"Advanced"},
  { q: "What makes a pitch weak?", a: "Good business + no valuation. Valuation + no thesis. Thesis + no catalyst. Upside only. No consensus awareness.", category: "Stock Pitch",difficulty:"Intermediate"},
  { q: "What is a catalyst?", a: "Event that causes the market to close the gap between price and value: earnings, product cycle, M&A, deleveraging.", category: "Stock Pitch",difficulty:"Intermediate"},
  { q: "How do you handle pushback?", a: "Don't get defensive. Show you've considered opposing views. Acknowledge risks. Defend with evidence.", category: "Stock Pitch",difficulty:"Intermediate"},
  { q: "Long vs short pitch?", a: "Long: market underestimates upside. Short: market overestimates durability/growth. Short requires stronger timing discipline.", category: "Stock Pitch",difficulty:"Intermediate"},
  { q: "How do you compare two stocks?", a: "Business quality, valuation, balance sheet, catalyst path, expected return distribution, portfolio fit.", category: "Stock Pitch",difficulty:"Intermediate"},
  { q: "What is downside analysis?", a: "Bear case assumptions, balance sheet risk, margin pressure, multiple downside, thesis invalidation. Think about losses before gains.", category: "Stock Pitch",difficulty:"Intermediate"},
  // MACRO (15)
  { q: "Why does macro matter for bottom-up investors?", a: "Macro affects discount rates, demand, credit conditions, earnings, valuations, currency, sector leadership.", category: "Macro",difficulty:"Intermediate"},
  { q: "How does inflation affect businesses differently?", a: "Companies with pricing power pass it through. Those without see margin compression. Input costs, labor, etc.", category: "Macro",difficulty:"Intermediate"},
  { q: "What do credit spreads tell you?", a: "Widening = stress, tightening financial conditions, risk-off. Credit often leads equity signals.", category: "Macro",difficulty:"Intermediate"},
  { q: "What is top-down vs bottom-up?", a: "Top-down: start with macro/sectors. Bottom-up: start with companies. Best investors integrate both.", category: "Macro",difficulty:"Intermediate"},
  { q: "How do different regimes favor different exposures?", a: "Falling rates → growth/duration. Strong growth → cyclicals/value. Recession → defensives/quality/duration (depends on inflation).", category: "Macro",difficulty:"Intermediate"},
  // PERFORMANCE (10)
  { q: "What is alpha?", a: "Return beyond benchmark/factor exposure. True security selection skill, net of factor bets and luck.", category: "Performance",difficulty:"Intermediate"},
  { q: "Sharpe vs information ratio?", a: "Sharpe: return per total vol. IR: excess return per tracking error. IR measures active management efficiency.", category: "Performance",difficulty:"Intermediate"},
  { q: "What is attribution analysis?", a: "Decomposing returns: sector allocation, security selection, factor exposure, currency. Explains where performance came from.", category: "Performance",difficulty:"Intermediate"},
  { q: "Gross vs net returns?", a: "Gross ignores costs. Net includes commissions, spreads, impact, taxes. Strategies must survive real implementation.", category: "Performance",difficulty:"Intermediate"},
  { q: "How should a manager discuss underperformance?", a: "Honestly. Was it bad process or temporary headwind? Show accountability and evidence the process remains sound.", category: "Performance",difficulty:"Intermediate"},
  // BEHAVIORAL (15)
  { q: "Why asset management?", a: "Business analysis + valuation + psychology + decision-making under uncertainty. Accountable for outcomes. Independent thinking + discipline.", category: "Behavioral",difficulty:"Intermediate"},
  { q: "How do you think about risk?", a: "Probability and severity of permanent capital loss. Includes leverage, liquidity, factor concentration, thesis risk. Not just vol.", category: "Behavioral",difficulty:"Intermediate"},
  { q: "Tell me about changing your mind on an investment.", a: "Show humility, evidence-based adaptation, no ego attachment. Good investors revise when facts change.", category: "Behavioral",difficulty:"Intermediate"},
  { q: "What is your investment philosophy?", a: "Be genuine. Value vs growth vs quality? Concentrated vs diversified? What edge do you believe in?", category: "Behavioral",difficulty:"Intermediate"},
  { q: "What do you think about the market right now?", a: "Frame regime (growth, inflation, rates). What matters most. What's priced in. Positioning implications. Not just headlines.", category: "Behavioral",difficulty:"Intermediate"},
  { q: "What makes a stock cheap?", a: "Not just low multiple. Cheap if price understates conservative future value and implied expectations are too pessimistic.", category: "Behavioral",difficulty:"Intermediate"},
  { q: "Tell me about yourself.", a: "Academic foundation → market interest → relevant experience → why AM is natural next step. Sound like an investor.", category: "Behavioral",difficulty:"Intermediate"},
  { q: "How would you build a portfolio?", a: "Mandate/benchmark → objective/risk budget → best ideas with diversification → sizing by conviction and risk → monitoring → sell discipline.", category: "Behavioral",difficulty:"Advanced"},
  { q: "What would make you sell a winner?", a: "Price reaches/exceeds fair value, better opportunity elsewhere, thesis changes, risk-reward deteriorates.", category: "Behavioral",difficulty:"Intermediate"},
  { q: "What would make you add to a loser?", a: "Only if thesis intact, price more attractive, and risk is manageable. Never average into denial.", category: "Behavioral",difficulty:"Intermediate"},
  // ═══ ADDITIONAL ANALYSIS (40) ═══
  {q:"What is a DuPont analysis?",a:"Decomposes ROE into: profit margin × asset turnover × equity multiplier. Shows whether returns come from margins, efficiency, or leverage.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is working capital intensity?",a:"WC as % of revenue. Low intensity = less cash tied up. Negative WC (deferred revenue businesses) is favorable.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is CapEx intensity?",a:"CapEx / Revenue. High intensity means more reinvestment required, less FCF conversion from EBITDA.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is the reinvestment rate?",a:"(CapEx - D&A + ΔWC) / NOPAT. How much of earnings must be reinvested. Lower = more cash available for shareholders.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is incremental ROIC?",a:"Change in NOPAT / change in invested capital. Shows return on new capital deployed. More forward-looking than average ROIC.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is the difference between gross and net debt?",a:"Gross = total debt. Net = total debt minus cash. Net debt is more relevant for leverage and EV calculations.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is debt maturity profile?",a:"Schedule of when debt comes due. Concentrated maturities create refinancing risk. Staggered is healthier.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is a credit rating?",a:"Assessment of default risk by agencies (S&P, Moody's, Fitch). Investment grade (BBB-/Baa3+) vs high yield.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is interest coverage?",a:"EBITDA / Interest. Measures ability to service debt. Below 2x is concerning. Critical for leveraged companies.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is the payout ratio?",a:"Dividends / Net Income. Shows how much earnings are returned vs retained. Sustainable if consistent with FCF.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is dividend yield?",a:"Annual dividend / share price. Income metric. High yield can signal value or distress - must investigate.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is a share buyback yield?",a:"Value of shares repurchased / market cap. Combined with dividend yield = total shareholder yield.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is total shareholder return (TSR)?",a:"Capital appreciation + dividends over a period. The complete return to equity holders.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is economic value added (EVA)?",a:"NOPAT - (Invested Capital × WACC). Positive EVA = company creates value above cost of capital.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is a quality screen?",a:"Filtering for high ROIC, stable margins, low leverage, strong cash conversion, consistent earnings. Identifies high-quality businesses.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is a value trap?",a:"Stock that looks cheap but keeps getting cheaper. Deteriorating business, structural decline, or governance issues.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is earnings yield?",a:"EPS / Price (inverse of P/E). Useful for comparing to bond yields and assessing relative value.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is the equity risk premium?",a:"Extra return investors demand for stocks over risk-free bonds. Historically ~5-6%. Varies with market conditions.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is a factor model?",a:"Decomposes returns into systematic factors: market, value, size, momentum, quality, volatility. Identifies what drives returns.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is smart beta?",a:"Index strategies weighted by factors (value, quality, low vol) rather than market cap. Between pure passive and active.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is ESG investing?",a:"Environmental, Social, Governance factors in investment decisions. Growing mandate constraint. Debate on alpha vs values.",category:"Analysis",difficulty:"Intermediate"},
  {q:"How do you analyze a bank?",a:"NIM, credit quality (NPLs, provisions), capital ratios (CET1), ROE, efficiency ratio. Different from industrial companies.",category:"Analysis",difficulty:"Intermediate"},
  {q:"How do you analyze an insurance company?",a:"Combined ratio, loss ratio, investment income, reserve adequacy, capital strength. Underwriting + investing.",category:"Analysis",difficulty:"Intermediate"},
  {q:"How do you analyze a REIT?",a:"FFO/AFFO, cap rates, occupancy, NOI growth, NAV premium/discount, leverage, dividend coverage.",category:"Analysis",difficulty:"Intermediate"},
  {q:"How do you analyze a commodity producer?",a:"Cost curve position, reserve quality, capital discipline, balance sheet, commodity price sensitivity.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is channel stuffing?",a:"Shipping excess product to distributors to inflate revenue. Red flag: revenue growth without corresponding sell-through.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is cookie jar reserves?",a:"Over-accruing reserves in good years and releasing in bad years to smooth earnings. Manipulation concern.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is bill-and-hold revenue?",a:"Recording revenue before shipping. Can be legitimate but is a common fraud mechanism. Requires scrutiny.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is same-store sales growth?",a:"Revenue growth from locations open at least a year. Strips out new store effects. Shows organic health.",category:"Analysis",difficulty:"Intermediate"},
  {q:"What is organic vs inorganic growth?",a:"Organic: internal growth. Inorganic: M&A-driven. Organic is generally more sustainable and higher quality.",category:"Analysis",difficulty:"Intermediate"},
  // ═══ ADDITIONAL VALUATION (25) ═══
  {q:"What is a normalized earnings approach?",a:"Adjust for cyclicality, one-time items, and unsustainable factors to estimate mid-cycle earning power. Better for cyclicals.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is replacement cost valuation?",a:"What it would cost to recreate the business from scratch. Provides a floor. Used for asset-heavy industries.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is a private market valuation?",a:"What PE or strategic buyers have paid for similar assets. Can reveal discount between public and private markets.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is EV/invested capital?",a:"Compares market value to capital employed. Premium to 1x suggests market expects returns above cost of capital.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is a cap rate?",a:"NOI / property value. Used for real assets. Lower cap rate = higher valuation relative to income.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is a dividend discount model?",a:"Equity value = PV of future dividends. Gordon Growth: P = D₁ / (r - g). Best for mature, stable dividend payers.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is a two-stage DDM?",a:"High growth for n years, then stable growth forever. More realistic than perpetual constant growth.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is implied growth rate?",a:"Growth rate embedded in current valuation. Reverse-engineer from P/E or DCF. Check if realistic.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is justified P/E?",a:"P/E = payout ratio / (r - g). Links P/E to fundamentals: growth, cost of equity, and payout. Not arbitrary.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is the EV/EBITDA vs P/E relationship?",a:"EV/EBITDA is pre-leverage, pre-D&A. P/E is post-everything. EV/EBITDA better for comparing across capital structures.",category:"Valuation",difficulty:"Intermediate"},
  {q:"When would you use EV/Revenue?",a:"Unprofitable companies, early-stage, high growth. Also useful when margins are expected to change significantly.",category:"Valuation",difficulty:"Advanced"},
  {q:"What is a breakup value?",a:"SOTP value if company were split into pieces. If > trading value, suggests conglomerate discount exists.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is a scarcity premium?",a:"Higher multiple for assets that are rare, hard to replicate, or have limited comparable opportunities.",category:"Valuation",difficulty:"Intermediate"},
  {q:"Why do growth stocks trade at higher multiples?",a:"More future value relative to current earnings. Longer duration = more sensitive to rates but higher potential.",category:"Valuation",difficulty:"Intermediate"},
  {q:"What is multiple compression?",a:"When a stock's valuation multiple declines. Can happen from rising rates, slowing growth, or shifting sentiment.",category:"Valuation",difficulty:"Intermediate"},
  // ═══ ADDITIONAL PORTFOLIO (20) ═══
  {q:"What is a factor tilt?",a:"Intentional portfolio bias toward a factor (value, momentum, quality). May be by design or unintentional.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is style drift?",a:"Manager deviating from stated investment style. Growth manager buying deep value stocks. Concerning for clients.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is rebalancing?",a:"Periodically adjusting portfolio back to target weights. Contrarian by nature - trim winners, add losers.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is a core-satellite approach?",a:"Core: passive/index allocation. Satellite: active positions for alpha. Balances cost efficiency with alpha potential.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is tax-loss harvesting?",a:"Selling losing positions to realize capital losses, offsetting gains. Improves after-tax returns.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is a risk budget?",a:"Allocating tracking error or active risk across positions/sectors. Ensures risk is taken intentionally.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is correlation risk?",a:"Risk that correlations spike during stress, reducing diversification benefit exactly when you need it most.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is crowding risk?",a:"Many investors in the same positions. If they exit simultaneously, forced selling amplifies losses.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is a stop-loss?",a:"Pre-set level to sell a losing position. Limits downside but can trigger in temporary volatility.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is position-level vs portfolio-level risk?",a:"Individual stock risk vs aggregate portfolio behavior. Diversification means portfolio risk < sum of position risks.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is a barbell strategy?",a:"Concentrating in extremes (very safe + very risky) and avoiding the middle. Used in bonds and equities.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is tactical asset allocation?",a:"Short-term deviations from strategic allocation based on market views. Must add value net of costs and timing risk.",category:"Portfolio",difficulty:"Intermediate"},
  {q:"What is strategic asset allocation?",a:"Long-term target mix of asset classes based on risk tolerance, return objectives, and time horizon.",category:"Portfolio",difficulty:"Intermediate"},
  // ═══ ADDITIONAL MACRO (15) ═══
  {q:"What is the yield curve telling you?",a:"Shape reflects growth and rate expectations. Steep = growth optimism. Flat/inverted = slowing expectations or tight policy.",category:"Macro",difficulty:"Advanced"},
  {q:"What is quantitative tightening?",a:"Central bank reducing balance sheet by not reinvesting maturing bonds. Tightens financial conditions.",category:"Macro",difficulty:"Intermediate"},
  {q:"What is the output gap?",a:"Difference between actual and potential GDP. Positive = overheating (inflation). Negative = slack (disinflation).",category:"Macro",difficulty:"Intermediate"},
  {q:"What is the Phillips curve?",a:"Inverse relationship between unemployment and inflation. Has weakened in recent decades but still relevant framework.",category:"Macro",difficulty:"Intermediate"},
  {q:"What is the neutral rate (r*)?",a:"Interest rate neither stimulating nor restraining economy. Unobservable - estimated. Guides central bank policy.",category:"Macro",difficulty:"Intermediate"},
  {q:"What is a risk-off trade?",a:"Selling risky assets (equities, HY credit) and buying safe havens (Treasuries, gold, yen). Flight to quality.",category:"Macro",difficulty:"Intermediate"},
  {q:"What are leading vs lagging indicators?",a:"Leading: predict future activity (PMI, yield curve, building permits). Lagging: confirm trends (unemployment, CPI).",category:"Macro",difficulty:"Intermediate"},
  {q:"What is PMI?",a:"Purchasing Managers' Index. Above 50 = expansion, below 50 = contraction. Leading indicator of economic activity.",category:"Macro",difficulty:"Intermediate"},
  {q:"How does a strong dollar affect US multinationals?",a:"Reduces foreign revenue when translated back. Hurts competitiveness. Benefits importers. Headwind for EM.",category:"Macro",difficulty:"Intermediate"},
  {q:"What is stagflation?",a:"High inflation + low growth + high unemployment. Worst combination for policymakers. Limits both fiscal and monetary tools.",category:"Macro",difficulty:"Intermediate"},
  {q:"What is fiscal policy vs monetary policy?",a:"Fiscal: government spending and taxation. Monetary: central bank rates and balance sheet. Both affect growth and inflation.",category:"Macro",difficulty:"Intermediate"},
  // ═══ ADDITIONAL STOCK PITCH (15) ═══
  {q:"How do you identify what consensus expects?",a:"Sell-side estimates, implied multiples, management guidance, earnings call sentiment, buy-side positioning surveys.",category:"Stock Pitch",difficulty:"Intermediate"},
  {q:"What is an asymmetric risk/reward?",a:"Upside potential significantly exceeds downside risk. Example: 50% upside, 15% downside. The best investment setups.",category:"Stock Pitch",difficulty:"Intermediate"},
  {q:"How do you build a bear case?",a:"Identify what goes wrong: margin compression, competitive threats, macro headwinds, balance sheet stress, multiple contraction.",category:"Stock Pitch",difficulty:"Advanced"},
  {q:"How do you build a bull case?",a:"Identify upside drivers: accelerating growth, margin expansion, capital return, positive revisions, re-rating.",category:"Stock Pitch",difficulty:"Advanced"},
  {q:"What is a base/bull/bear probability weighting?",a:"Assign probabilities to scenarios. Expected value = Σ(probability × return). Shows discipline vs single-point forecasting.",category:"Stock Pitch",difficulty:"Intermediate"},
  {q:"How do you defend against 'why not the competitor instead?'",a:"Compare business quality, valuation, balance sheet, catalyst path, and risk-reward. Show you considered alternatives.",category:"Stock Pitch",difficulty:"Intermediate"},
  {q:"What is a short pitch?",a:"Thesis that stock is overvalued. Must identify: what expectations are too high, catalyst for disappointment, timing, squeeze risk.",category:"Stock Pitch",difficulty:"Intermediate"},
  {q:"What is a pair trade pitch?",a:"Long one stock, short a related one. Express a relative view. Market-neutral if balanced.",category:"Stock Pitch",difficulty:"Intermediate"},
  // ═══ ADDITIONAL PERFORMANCE (10) ═══
  {q:"What is the Sortino ratio?",a:"Return / downside deviation. Better than Sharpe because it only penalizes harmful volatility (below target).",category:"Performance",difficulty:"Intermediate"},
  {q:"What is max drawdown?",a:"Largest peak-to-trough decline. Shows worst-case experienced loss. Critical for risk-averse clients.",category:"Performance",difficulty:"Intermediate"},
  {q:"What is the Calmar ratio?",a:"Annualized return / max drawdown. Measures return relative to worst experienced loss.",category:"Performance",difficulty:"Intermediate"},
  {q:"What is batting average?",a:"% of periods beating the benchmark. Measures consistency of outperformance.",category:"Performance",difficulty:"Intermediate"},
  {q:"What is up-capture vs down-capture?",a:"Up-capture: % of benchmark gains captured. Down-capture: % of benchmark losses experienced. Want high up, low down.",category:"Performance",difficulty:"Intermediate"},
  {q:"What is style analysis?",a:"Decomposing returns into factor exposures (value, growth, size) to determine what's driving performance.",category:"Performance",difficulty:"Intermediate"},
  {q:"What is net exposure?",a:"Long % - Short %. 100% net long = fully invested long-only. 0% = market neutral.",category:"Performance",difficulty:"Intermediate"},
  {q:"What is gross exposure?",a:"Long % + Short %. 150% gross = leveraged. Shows total capital deployed.",category:"Performance",difficulty:"Intermediate"},
  // ═══ ADDITIONAL BEHAVIORAL (15) ═══
  {q:"Describe your investment research process.",a:"Idea generation → business analysis → valuation → thesis development → risk assessment → portfolio fit → monitoring.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What book about investing has influenced you most?",a:"Pick one you actually read. Explain the key takeaway and how it shaped your thinking. Show intellectual curiosity.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"How do you handle being wrong on an investment?",a:"Acknowledge it, analyze what went wrong (thesis error, timing, external shock), learn from it, adjust process.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What is behavioral finance?",a:"Study of psychological biases affecting investment decisions: anchoring, loss aversion, herding, overconfidence, recency.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What is confirmation bias?",a:"Seeking information that confirms existing beliefs while ignoring contradictory evidence. Dangerous for investors.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What is anchoring bias?",a:"Over-relying on first piece of information (initial price, analyst target). Can prevent updating views with new data.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What is loss aversion?",a:"Pain of losses exceeds pleasure of equal gains (~2x). Causes investors to hold losers too long and sell winners too early.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What is herding?",a:"Following the crowd. Feels safe but creates crowded trades and amplifies booms/busts.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What is the disposition effect?",a:"Tendency to sell winners too early (lock in gains) and hold losers too long (avoid realizing losses).",category:"Behavioral",difficulty:"Intermediate"},
  {q:"What is recency bias?",a:"Overweighting recent events. After a crash, investors are too cautious. After a boom, too aggressive.",category:"Behavioral",difficulty:"Intermediate"},
  {q:"How do you manage your own biases?",a:"Written process, pre-mortems, devil's advocate, checklist discipline, journaling decisions and reasoning.",category:"Behavioral",difficulty:"Intermediate"},
  // ── ADVANCED INTERVIEW FLASHCARDS (150) — uploaded 2026-05-18 ──
  { q: "Walk me through how you'd construct a portfolio for a university endowment with a 30-year horizon versus a defined benefit pension that's 90% funded.", a: "The endowment can take real liquidity risk and reach into private equity, venture, real assets, and concentrated public equity because its spending rate is the binding constraint, not mark-to-market volatility. A 90%-funded pension is the opposite: every drawdown widens the funding gap and forces the sponsor to contribute, so you build a liability-driven structure with long-duration fixed income matched to liability duration and a smaller return-seeking sleeve. The endowment optimizes for compounding over decades; the pension optimizes for funded status volatility. You'd also use very different benchmarks - a policy portfolio with illiquidity premium expectations versus a liability-discount-rate benchmark. The biggest mistake is treating them as the same investor with different time horizons.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If two assets have a historical correlation of 0.3, what assumptions are you making by using that in portfolio construction, and what could go wrong?", a: "You're assuming correlation is stationary, but realized correlations move sharply with regime. In stress events, cross-asset correlations converge toward 1 precisely when you need diversification most - 2008, March 2020, and the 2022 rates-driven sell-off are all examples. You're also implicitly assuming the joint distribution is approximately Gaussian, when the real risk lives in the tails where dependence structures change. A better practice is to stress correlation matrices to 0.7+ in your downside scenarios and size positions to survive that environment rather than the historical one. Correlation is descriptive of the past, not predictive of the next crisis.", category: "Portfolio", difficulty: "Advanced" },
  { q: "When would you use risk budgeting over equal-weighted allocation, and what are the practical pitfalls?", a: "Risk budgeting is appropriate when you have asymmetric conviction across positions and want each dollar of risk - not each dollar of capital - working proportionally to your edge. The pitfall is that it forces you to estimate vol and correlations precisely, and those estimates are unstable, especially during regime shifts. Low-vol assets get over-levered, which is how risk parity strategies got hurt in 2022 when bonds and stocks sold off together. The other trap is that risk budgeting can mask concentration in factor exposure even when position-level risk looks balanced. I'd use it as a check on equal-weighting, not as the primary allocation framework.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through how you'd size a position with high conviction but high uncertainty around the timing of the catalyst.", a: "Position size should be a function of conviction times asymmetry, discounted by timing uncertainty. If you're high-conviction on the thesis but the catalyst window is two-to-five years, you size smaller than a catalyst-rich situation because optionality decays and opportunity cost is real. I'd anchor to a base position - say 2-3% in a long-only book - and reserve dry powder to add on weakness or on time-stamped signals that the catalyst is approaching. The mistake junior analysts make is sizing on conviction alone and ignoring path dependency. Concentrated PMs like Bill Miller have publicly said timing risk is what kills compounders, not thesis risk.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If the Sharpe ratios of two managers are identical but their information ratios differ significantly, what does that tell you?", a: "Sharpe measures total return per unit of total volatility; information ratio measures active return per unit of tracking error. Identical Sharpes with different IRs means one manager is earning their return through market beta and the other is genuinely generating alpha relative to a benchmark. The lower-IR manager may just be a beta vehicle dressed up as active, which justifies index-fund fees, not active fees. You'd want to see the underlying beta exposures and decompose returns into systematic versus idiosyncratic sources before paying for the alpha story. IR is the better fee-justification metric for an active mandate.", category: "Portfolio", difficulty: "Advanced" },
  { q: "A manager has a tracking error of 2% but posts an -8% return versus benchmark in a single quarter. How is that possible?", a: "Tracking error is the annualized standard deviation of relative returns, so the realized number is sampled from a distribution - any single quarter can be an outlier. A four-standard-deviation move on 2% annualized TE is roughly that range, and four-sigma events happen far more frequently than a Gaussian assumption implies. The more interesting question is whether the underperformance came from a single factor exposure - growth, leverage, low-quality - that wasn't visible in the rolling TE estimate. Backward-looking TE understates regime risk. I'd want a Brinson-style attribution and a factor decomposition before concluding it was bad luck versus bad construction.", category: "Portfolio", difficulty: "Advanced" },
  { q: "When does diversification stop adding value to a portfolio, and how do you measure that?", a: "Marginal benefit from adding names declines sharply after about 20-30 stocks in a single-factor portfolio because most idiosyncratic variance has been diversified away. Beyond that, you're adding correlation with the benchmark, not reducing risk. The way to measure it empirically is to look at portfolio variance reduction per added name and stop when the curve flattens, or look at the active share - once active share drops below 60%, you've largely become a closet indexer. A more nuanced view is that diversification has different value in different regimes, and concentrated portfolios can outperform precisely because they sacrifice average-case diversification for tail conviction.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through your framework for deciding active versus passive within an asset allocation.", a: "I anchor to market efficiency by sub-asset class. Large-cap US equities are highly efficient and active managers struggle to net of fees beat the S&P, so I default to passive there. Small-cap, emerging markets, high-yield credit, and frontier markets show more persistent active manager dispersion and lower information ratios for indexers, which is where active fees earn their keep. Within active, I'd separate true alpha sources from factor exposures that are now available cheaply through smart-beta ETFs. The framework is: is there genuine inefficiency, can a manager harvest it, and is the after-fee, after-tax expected return materially above the alternative?", category: "Portfolio", difficulty: "Advanced" },
  { q: "If you run a concentrated 20-stock portfolio versus a 100-stock portfolio with the same beta, what tradeoffs are you making?", a: "Same beta means similar systematic exposure but the 20-stock portfolio has materially higher idiosyncratic risk - each name is 5% of the book versus 1%. That means your stock selection skill needs to actually exist, because a single blow-up hurts much more. The upside is that you can express conviction, and on a forward basis your returns reflect your views, not the index. The 100-stock book is more like factor exposure dressed up as active management with high active share but low active risk. The right structure depends on whether you're paid to make calls or to deliver smooth excess returns relative to a benchmark.", category: "Portfolio", difficulty: "Advanced" },
  { q: "A client wants a 6% real return target but won't tolerate more than a 10% peak-to-trough drawdown. How do you respond?", a: "I'd push back: the combination is roughly inconsistent over reasonable horizons. Historical 60/40 has averaged 5-6% real but with 20%+ drawdowns, so to compress drawdowns to 10% you'd need to cut equity beta materially, which lowers expected return below 6%. You can buy tail hedges to clip the drawdown, but the option premium is a structural drag on the real return. The honest conversation is that they have to relax one constraint - either accept lower returns, accept larger drawdowns, or pay for explicit tail risk insurance. Letting a client believe both are achievable is how you lose the mandate after the first bad year.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through how you'd rebalance a 60/40 portfolio after equities rallied 30% year-to-date in March.", a: "First, check whether the drift breaches your bands - if you set 5% bands on a 60% equity target, you'd be at roughly 67% equity and need to trim. The mechanical decision is to sell equities and buy bonds back to target. The judgment overlay is whether you actually want to mean-revert into bonds given current yields and macro setup, or whether you want to widen the bands to let momentum run. Tax-aware investors also consider realizing gains, harvesting losses elsewhere first, and using new contributions to rebalance without selling. The discipline of rebalancing is one of the few things that's worked over multiple regimes; abandoning it because the market feels a certain way is where investors burn returns.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If implied volatility on the S&P spikes from 15 to 35, how does that change your portfolio decisions?", a: "Higher implied vol means option-based hedges are expensive to put on, so the time to buy protection was before the spike, not after. It also reprices forward expected returns higher because vol is mean-reverting, so the equity risk premium has effectively widened. I'd be cautious about selling vol as a yield-enhancement strategy at low implied vol levels and more aggressive about it when realized lags implied. Operationally, I'd review margin requirements on any structured trades, since broker calls during vol spikes are how leveraged investors get forced out. The instinct to derisk when vol spikes is usually backwards - you want to lean in if your thesis hasn't broken.", category: "Portfolio", difficulty: "Advanced" },
  { q: "What's the case against rebalancing on a calendar basis versus on bands?", a: "Calendar rebalancing is mechanical and easy to govern but it's path-dependent in unhelpful ways - if you rebalance Q4 every year and the market crashes Q3, you've locked in the loss. Band-based rebalancing only trades when drift breaches thresholds, so it respects trends and reduces unnecessary turnover and tax drag. The downside of bands is governance - it can feel discretionary, and clients often want predictability. Most institutional investors run hybrid systems: calendar checks with bands as triggers within them. The bigger issue is that both methods assume mean reversion is the right model; in a strongly trending market, both methods underperform a buy-and-hold strategy.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through how you'd handle liquidity during a 2008-style credit event in a multi-asset portfolio.", a: "Step one is mapping liquidity tiers across your book - what can you sell in a day at small spread impact, what takes a week, and what's gated entirely. Step two is meeting redemption and rebalancing demands from the most liquid pool first to preserve the ability to opportunistically buy at distressed prices, not the other way around. Forced sellers in 2008 had to liquidate their best, most liquid names to meet redemptions, which destroyed long-term IRR. Step three is communicating with stakeholders before the panic - pre-arranged credit lines, transparent gate policies, and managed expectations. The strategic lesson is that liquidity is not a single state; it's a portfolio property to be managed at all times, not just in a crisis.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If you're benchmarked to the S&P 500 but your absolute return mandate is 8%, how do those two goals conflict?", a: "They conflict on every active decision. If you believe equities will return 4% next year, the benchmark tells you to hold equities; the absolute return mandate tells you to find something else. In a 25% S&P year, beating the benchmark by 200bps still leaves you at 27% - both goals look fine - but in a -20% year, hitting 8% means -28% tracking error, which is a career-ending number even if it's the right outcome for the client. The honest answer is that dual mandates are a forcing function for closet indexing during bull markets and large active risk during bear markets, which is the opposite of what you want. You need explicit prioritization in the IPS.", category: "Portfolio", difficulty: "Advanced" },
  { q: "When does high portfolio turnover destroy value, and when does it create value?", a: "Turnover destroys value when it's reactive - chasing momentum, exiting at vol spikes, or trading around news without an edge - because each round-trip eats spread and taxes. It creates value when it reflects genuine information arrival: catalyst-driven exits, thesis-break rotations, or tactical positioning around earnings windows where you have differentiated information. The metric to watch is alpha per unit of turnover, not turnover itself. Quant strategies can have 200%+ turnover and still compound because each trade is statistically positive; a discretionary book at 100% turnover is usually closet trading. Tax-aware investors face an additional drag of 20-30bps per 100% of turnover in taxable accounts.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If a factor exposure analysis shows your active portfolio is 80% explained by value and quality factors, what does that mean for your fees?", a: "It means your investors are paying 100bps for what they could get from a smart-beta ETF at 15bps. The 20% residual is your true alpha contribution and it has to be persistent and economically meaningful to justify the active fee structure. Many actively-managed funds are factor portfolios in disguise, which became a problem once factor ETFs proliferated and made the alternative explicit. The strategic response is either to demonstrate alpha is real and sustainable, charge lower fees commensurate with the actual active share, or differentiate on something the factor exposure can't replicate - concentration, capacity, or thematic positioning.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through the difference between tactical and strategic asset allocation and when you'd lean on each.", a: "Strategic asset allocation is the long-term policy mix derived from objectives, risk tolerance, and capital markets assumptions - it changes only when those underlying inputs change. Tactical asset allocation overlays shorter-horizon views, leaning into or out of asset classes based on valuation, momentum, or macro signals, typically within bounded deviations from policy. Most academic and practitioner evidence shows strategic allocation explains the vast majority of long-term return variance, so tactical decisions should be modest in size and have clear edge. I'd lean tactical when valuations are at extremes - the late-1990s tech setup, 2022 bond yields - because the asymmetry justifies deviating from policy. Otherwise, the cost of being wrong tactically usually exceeds the average benefit.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If you held 60/40 from 1980 to 2020 and the same 60/40 from 2020 to 2025, why might performance look fundamentally different?", a: "1980 to 2020 was a 40-year bond bull market - the 10-year yield went from 15% to 1% - so the bond sleeve gave you both income and meaningful capital appreciation, and it diversified equities. From 2020 onward, you started with bonds yielding nothing and rates rose, so bonds delivered negative real returns and positive correlation with stocks in 2022, breaking the diversification thesis. The historical 60/40 Sharpe of around 0.8 was a regime artifact, not a stable property of the portfolio. Investors who assumed forward returns would match historical returns were anchoring on the wrong sample. The same allocation behaves differently when the starting conditions change.", category: "Portfolio", difficulty: "Advanced" },
  { q: "How would you think about adding a 10% allocation to private credit to a traditional 60/40 portfolio?", a: "First, decide whether you're substituting for fixed income or for equities, because the answer changes what the allocation actually does. Private credit's higher yield comes with illiquidity, manager selection risk, and mark-to-model smoothness that understates true volatility. The diversification benefit relative to public credit is often overstated because the underlying exposure is similar - senior secured loans to mid-market companies. If you're funding it from fixed income, you're picking up 300-500bps of yield but lengthening lockups and giving up daily liquidity. The honest case is that it's an attractive carry trade with risks that don't show up until a default cycle, which is exactly what's coming through 2026-2027 in the leveraged loan market.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through downside protection strategies and rank them by cost versus effectiveness.", a: "Put options are the cleanest but the most expensive - you pay an explicit premium every period and the carry is structurally negative outside of crisis. Put spread collars cap upside to fund the put, which works when you'd be happy clipping 15-20% return for protection on the next 15% down. Cash and short-duration Treasuries are cheap and effective in equity drawdowns but lose to inflation over time. Trend-following CTAs have historically been the best convex hedge - they were one of the few things that worked in 2022 - but they have crisis alpha that's regime-dependent. Tail risk funds are the most expensive in carry and pay off in true crashes, suitable only if you can stomach decade-long negative returns to harvest the rare big payoff.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If two long-only managers have identical returns but one runs at 2x the gross exposure, how do you compare them?", a: "On a risk-adjusted basis the higher-gross manager is materially worse because leverage amplifies drawdowns and increases gap risk. Their returns reflect more market beta, not skill, and in any drawdown event the higher-gross book will compound losses faster. The right metric is return on invested capital, not return on equity, and information ratio relative to actual risk taken. A useful diagnostic is to compute the manager's effective beta and ask whether the excess return justifies the additional risk - it usually doesn't once you adjust. Long-only managers using leverage are often a regulatory or marketing arbitrage, not a genuinely different strategy.", category: "Portfolio", difficulty: "Advanced" },
  { q: "When does adding more managers actually increase risk rather than diversify it?", a: "When the marginal manager is correlated with what you already own, you're not adding diversification - you're adding fee drag and operational complexity. This is common in multi-manager equity programs where you end up holding the same large-caps through ten different vehicles. The other risk is style drift across managers converging on similar trades during regime shifts, which means realized diversification in stress is lower than historical correlations suggest. There's also a diligence cost - each manager needs operational due diligence, monitoring, and risk oversight that scales sub-linearly with quality. Most academic evidence suggests diminishing returns past 5-7 truly differentiated managers; beyond that, you're paying for the illusion of diversification.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through how you'd build a barbell portfolio and when that structure makes sense.", a: "A barbell concentrates risk at two extreme ends and avoids the middle - say, 80% in cash and short Treasuries paired with 20% in high-convexity, high-conviction equities or options. The thesis is that the middle is where you take risk without commensurate return, while the extremes give you safety and lottery-ticket optionality. It makes sense when you have very specific tail views, like macro dislocations, or when you want to control downside while keeping upside participation through asymmetric positions. The risk is that the cash sleeve drags during prolonged bull markets and you don't size the convex book large enough to matter when you're right. Nassim Taleb popularized this structure but it requires either deep conviction or genuine optionality access most investors don't have.", category: "Portfolio", difficulty: "Advanced" },
  { q: "If your portfolio is up 15% but your benchmark is up 18%, how do you have the conversation with the client?", a: "Lead with attribution - what drove the underperformance, was it style, factor exposure, security selection, or timing. Then frame it against your investment process: did the gap come from following your process or from deviating from it? Clients tolerate underperformance from disciplined adherence to thesis far better than underperformance from drift or panic. Reference rolling-period performance, not just YTD - a single year tells you almost nothing about manager skill in a long-only context. The goal is to convert the conversation from result to process; if the process is sound, results normalize over time, and you protect the relationship through the inevitable rough patches.", category: "Portfolio", difficulty: "Advanced" },
  { q: "Walk me through what makes a great long versus a great compounding hold versus an event-driven trade.", a: "A great long is a mispriced security with a clear path to re-rating within a definable horizon - the gap between price and fair value is the alpha and you need a catalyst or time to close it. A compounding hold is different: you're buying a business that reinvests at high returns on capital, so even a flat multiple over time compounds wealth through earnings growth. An event-driven trade is structurally lower duration - merger arb, spin-offs, recap announcements - where the payoff is bounded and your edge is process and access, not fundamental conviction. The mistake is treating them as the same instrument; each requires different position sizing, monitoring intensity, and exit discipline.", category: "Analysis", difficulty: "Advanced" },
  { q: "If consensus has a stock at $100 and you think it's worth $150, walk me through how you'd validate that gap is real and not a modeling error.", a: "First, decompose the gap into its drivers - is it revenue growth, margin expansion, multiple expansion, or all three - and stress-test each assumption against base rates. Then triangulate against the bear case: what does a sell-side analyst at $90 assume that you don't? Pressure-test through reverse engineering: at the current price, what does the market need to believe, and is that internally consistent? Talk to the company, customers, competitors, and former employees to validate or disprove your differentiated assumptions. If you can't articulate exactly which sentence in the consensus model is wrong, your gap is probably noise.", category: "Analysis", difficulty: "Advanced" },
  { q: "When is high reported earnings quality actually a red flag?", a: "When margins are at multi-year peaks during a cyclical industry's upcycle, current earnings overstate normalized power. Tax rate normalization, stock-based comp adjustments, and aggressive capitalization of expenses also distort the picture. Companies with one-time gains pushed into operating income - lawsuit settlements, real estate sales, contract terminations - often look high-quality on the print and look mediocre on a multi-year basis. The other tell is when free cash flow has consistently lagged accrual earnings by 20%+ for multiple years; that's a working capital or capex story that suggests earnings aren't translating into cash. High earnings quality during a setup that historically reverses is a setup for disappointment.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you evaluate management's capital allocation track record.", a: "Build a five-to-ten year ledger of every major capital decision - M&A, buybacks, dividends, capex, debt reduction - and compute return on that incremental capital. Compare announced returns at the time of the deal to actual realized returns three to five years later. Watch for patterns: do they buy back stock at the highs and stop at the lows, do their acquisitions earn the cost of capital, do they ramp capex into cyclical peaks. The best capital allocators are buyers at the bottom of cycles and disciplined about not chasing growth at any price. Track records compound - a management team that's destroyed capital for ten years rarely starts creating it without a leadership change.", category: "Analysis", difficulty: "Advanced" },
  { q: "If a company's been growing at 25% for five years, how do you decide if that's secular or cyclical?", a: "Map the growth to underlying drivers - is it volume from new customers, price increases, geographic expansion, or share gains? Secular growth shows up in the same metric independently of macro conditions; cyclical growth correlates tightly with broader cycle indicators like ISM, housing starts, or capex. Look at the customer base: secular winners typically diversify their customer concentration over time, cyclicals see customer concentration follow the cycle. Compare historical periods - did the company grow through the last recession or did it crater? The most expensive mistake in growth investing is paying secular multiples for cyclical earnings near a peak.", category: "Analysis", difficulty: "Advanced" },
  { q: "What's your framework for assessing moat durability beyond just looking at margins?", a: "Margins are an output; moat sources are inputs. I look at five: network effects (does each new user make the product more valuable), switching costs (what does it cost a customer to leave), scale economics (does cost per unit fall faster than competitors), intangibles like brand and IP, and regulatory or licensing barriers. The durability question is whether the source is reinforcing over time or eroding - Amazon's scale moat compounds, BlackBerry's switching costs evaporated when iPhones appeared. I also look at the moat through the customer's eyes: would they switch for a 10% price increase, a 20% increase, a 50% increase? Real moats survive material price increases without volume loss.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through unit economics analysis for a subscription business.", a: "Start with customer acquisition cost and lifetime value - LTV/CAC of 3x is the rough threshold for a healthy SaaS business, with sub-12-month payback period indicating efficient capital deployment. But the metric that matters most is gross retention and net retention; gross tells you customer churn, net adds back expansion revenue. Net revenue retention above 110% means the existing book grows faster than churn loses customers, which is the magic of compound subscription value. Gross margins matter too - a 40% gross margin SaaS is really a managed services business in disguise. Then layer in CAC payback trajectory by cohort: improving payback over time means the model is scaling efficiently.", category: "Analysis", difficulty: "Advanced" },
  { q: "If a company has 80% incremental margins on a 20% gross margin base, what does that tell you about operating leverage?", a: "Either the cost structure is very fixed and they're scaling into capacity, or there's a mix shift toward higher-margin offerings, or there's a one-time benefit that won't repeat. High incremental margins on low base margins is mathematically possible but usually unsustainable - at some point you hit capacity constraints or the mix saturates. The bullish read is operating leverage works in your favor going forward; the bearish read is you're seeing the peak and the next downturn will reverse it. I'd dig into whether incremental revenue is true scale or just mix shift, because the implications for normalized margins differ significantly. Operating leverage cuts both ways and dispersion of outcomes is wide.", category: "Analysis", difficulty: "Advanced" },
  { q: "When would you use EV/EBITDA over EV/Sales over P/E for a given sector?", a: "EV/EBITDA works for capital-light, stable cash flow businesses where D&A is a meaningful share of accounting expense and capital structures vary across comps. EV/Sales is useful for early-stage, high-growth companies where margins are still scaling or aren't representative - software pre-profitability, biotech, certain consumer brands. P/E is fine for mature businesses with stable capital structures and limited M&A activity, but it's distorted by tax rate, leverage, and non-cash items. For banks and insurers, you use price-to-tangible-book and ROTCE because earnings are output of a complex liability structure. The right multiple is the one that strips out distortions and isolates the unit of value creation.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd value a quality compounder differently than a deep value name.", a: "A compounder is valued on forward earnings power three to five years out, discounted back at a reasonable rate - you're underwriting the reinvestment runway, not the current snapshot. Multiple expansion is not part of the underwriting; the math should work even if the multiple compresses. Deep value is the opposite: you're buying a discount to current intrinsic value with a catalyst to close the gap, and your return comes from re-rating, not earnings growth. The risk profiles are mirror images - compounder risk is paying up for growth that doesn't materialize, value risk is the discount being permanent. The mental error is using compounder logic on cyclicals or value logic on a true compounder.", category: "Analysis", difficulty: "Advanced" },
  { q: "When is paying a 30x P/E cheap and when is paying 8x P/E expensive?", a: "30x is cheap when forward earnings growth is 25%+ for a multi-year window with high incremental ROIC - the PEG ratio is well below one and you're getting a long-duration cash flow stream at a reasonable discount rate. 8x is expensive when earnings are at a cyclical peak about to revert, leverage is high, or the business is in secular decline - in 2007 many homebuilders traded at 6x and went to zero. Multiples have to be evaluated against normalized earnings, growth durability, and capital intensity, not just compared to history. A 30x stock with reinvestment at 25% ROIC and 10-year visibility is mathematically cheaper than an 8x cyclical at peak earnings. Naive multiple comparison is a great way to lose money in both directions.", category: "Analysis", difficulty: "Advanced" },
  { q: "What catalysts make for the best long ideas versus ones that look like catalysts but don't actually matter?", a: "The best catalysts force a re-pricing of consensus assumptions - earnings beats that change forward growth trajectory, capital allocation decisions that unlock value, spin-offs that separate quality businesses from drag, or regulatory changes that re-rate the entire group. Weak catalysts that look real but don't move stocks include sell-side upgrades, conference presentations, and minor product launches that don't change the financial trajectory. The test is whether the catalyst would actually move the model - if you can't write down a dollar of EPS change from the catalyst, it's a marketing event, not a re-pricing event. The cleanest catalysts have a specific date and a specific dollar impact you can underwrite.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd analyze a company burning $200M in FCF annually but growing revenue 50%.", a: "First, decompose the burn: is it growth investment in S&M and R&D that's funding the 50% growth, or is it core operating loss before any growth investment? If you can isolate steady-state economics, you can model what FCF looks like when growth normalizes. The Rule of 40 - growth plus free cash flow margin - is a useful benchmark; sub-40 means the model isn't working at scale. Then ask if the customer acquisition is actually compounding - are CAC payback periods getting shorter, is net retention strong, is the magic number above one? A company burning to fund efficient growth is investing; a company burning because the unit economics don't work is failing. The numbers look identical on the income statement and diverge in five years.", category: "Analysis", difficulty: "Advanced" },
  { q: "If a stock dropped 30% on a guidance cut, how do you decide if it's temporary or structural?", a: "Pull the transcript and identify which line items are guided lower - volume, price, mix, costs - and ask whether each driver is cyclical or structural. Temporary issues tend to be inventory adjustments, weather impacts, customer destocking, or one-time geographic disruptions; structural issues are share loss, demand destruction, or margin compression from new entrants. Look at the competitive set: are peers reporting similar weakness or is this idiosyncratic? Talk to channel checks within a few weeks to validate management's framing. The trap is anchoring on the price drop as if magnitude implies severity; sometimes 30% is the right adjustment, sometimes it's an overreaction, and the answer depends entirely on what's actually changed in the business.", category: "Analysis", difficulty: "Advanced" },
  { q: "When is buying back stock the wrong capital allocation decision even if the stock looks cheap?", a: "When the balance sheet is stretched and a downturn would force forced selling or refinancing at distressed rates. When the business needs reinvestment that earns above cost of capital - taking capital out for buybacks instead of investing in projects with 20% IRRs is value-destructive. When management's track record on capital allocation is poor and they're buying because the analyst day is coming up, not because the math works. When the buyback is funded by debt issuance during an aggressive cycle of low rates, you're essentially levering up the company at the peak. The right test is whether the buyback is the best use of capital on a risk-adjusted basis, not whether the stock seems cheap on a P/E.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd assess a CEO who's been at the helm for 15 years and the stock has compounded at 18%.", a: "Strip out market beta and sector tailwinds - 18% with a 12% market and a 15% sector is mediocre, 18% in a flat sector is exceptional. Then decompose: how much of the return came from organic earnings growth, multiple expansion, capital returns, or accretive M&A. Look at insider sales and buys over the period to see if their actions match their narrative. Review the strategic pivots they made and whether they were on top of disruption or behind it. The best executives compound capital through changing conditions; the lucky ones rode a single secular wave. Distinguishing the two is the work.", category: "Analysis", difficulty: "Advanced" },
  { q: "If management is buying stock personally, is that a buy signal? What would change your answer?", a: "Open-market purchases by C-suite executives have historically been a positive signal because they're putting at-risk capital where their mouth is. The signal weakens if the buys are small relative to their existing position, if they're funded by simultaneous option exercises, or if the company is in a buyback program where insider purchases are common compliance. What would change my answer is if the company has cyclical headwinds that the insider doesn't fully understand, or if a long-tenured executive is buying out of confirmation bias. Buys near a stock low have been historically more informative than buys near highs. The signal is most powerful when the buyer is not a serial purchaser and the size is meaningful.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd analyze a company where 70% of revenue comes from one product line.", a: "The first question is whether the product line is competitively advantaged or whether concentration is a function of having one bet that's working. Then assess product lifecycle - is the product mid-cycle, late-cycle, or already declining - and how the company is positioning for the next product. Look at customer concentration within the product line too; a single product going to a single customer base is concentration squared. Pricing power, regulatory exposure, and technological obsolescence risk all need to be modeled at the product level, not the company level. The valuation has to reflect single-product risk - Apple is allowed a premium because iPhone is reinforced by services; a single-drug biotech is not.", category: "Analysis", difficulty: "Advanced" },
  { q: "When does a wide moat company become a value trap?", a: "When the moat is protecting a business model that's losing relevance - Kodak's distribution and brand were powerful right until digital photography made them irrelevant. When the company stops reinvesting in the moat and uses cash to buy back stock or pay dividends instead. When the moat protects a stable cash flow stream but earnings power is gradually eroding from secular pressures. The setup is dangerous because the metrics look strong - high margins, high ROIC, strong balance sheet - even as the underlying business decays. Newspapers in 2005 looked phenomenal on every traditional metric; the moat was real but defending a shrinking market. The test is whether the moat protects a growing or shrinking economic territory.", category: "Analysis", difficulty: "Advanced" },
  { q: "If the company's TAM looks huge but penetration has stalled at 10%, what's likely happening?", a: "Either the TAM is overstated, the product-market fit isn't as broad as management claims, or there's a friction point preventing adoption beyond a specific buyer profile. Stalling at 10% is a common pattern when the early adopter pool is exhausted and the mainstream market requires different positioning, pricing, or sales motion. Sometimes the actual addressable market is much smaller than the headline TAM and you've already saturated it. Sometimes the product needs a re-architecture to serve the next wave. The key diagnostic is whether new customer acquisition is slowing, whether ACVs are compressing, and whether sales cycles are lengthening - those are the early signals that growth has hit a natural ceiling.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how to evaluate a roll-up acquirer and what red flags you'd watch for.", a: "Strip out acquisition accounting and look at organic growth - a roll-up that's only growing through acquisitions is masking underlying business decline. Compare announced synergies to realized synergies over time; serial acquirers often miss their targets by 30%+. Look at the cadence and size of deals - accelerating deal flow into rising multiples is a classic late-cycle setup. Track integration metrics: are acquired margins improving toward parent margins, or is the parent's margin sliding toward acquired levels? The single biggest red flag is when the acquisition currency is the stock itself and management's narrative depends on the multiple staying elevated. Roll-ups work when the unit economics genuinely improve under common ownership and break when M&A is the business model rather than a tool.", category: "Analysis", difficulty: "Advanced" },
  { q: "If a company is earnings power-positive but reports GAAP losses every quarter, how do you bridge that?", a: "Common sources of the gap are stock-based compensation, amortization of acquired intangibles, deferred revenue accounting, and one-time integration costs. SBC is real economic cost to existing shareholders even if it doesn't hit cash - the right way to evaluate it is whether the company's diluted share count is growing materially. Amortization of acquired intangibles is non-cash but reflects capital that was deployed; whether to add it back depends on whether you've already accounted for the M&A spend separately. Adjusted EBITDA without SBC at high-growth software companies is often the most flattering metric and the least reliable as a long-term economic measure. The right framework is to assess steady-state free cash flow power after normalized growth investments and reasonable share dilution.", category: "Analysis", difficulty: "Advanced" },
  { q: "When is a sum-of-the-parts valuation actually useful and when is it a crutch?", a: "SOTP is useful when a conglomerate has genuinely separable businesses with different risk profiles, growth rates, or capital intensities - a Berkshire-style holding company or a media business with theme parks, streaming, and cable. It's a crutch when the businesses are operationally integrated and the implied parts couldn't actually exist independently; you're just sticking numbers together. Activists love SOTP because it justifies forced separation, but the value creation depends on whether separation actually unlocks the discount or just creates standalone overhead. The test is whether you can imagine a credible buyer or spin structure for each piece. If the answer is in theory, your SOTP is a marketing tool, not a valuation.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd test whether a competitive advantage is widening, holding, or eroding.", a: "Track three signals over rolling four-quarter windows: market share trajectory, price realization versus inputs, and customer retention or renewal economics. Widening advantage shows up as share gains paired with price increases that don't trigger volume loss - classic Apple in the 2010s. Holding advantage is share-stable with margins in line with historical levels and customers renewing at expected rates. Erosion shows up first in concessions - small price discounts to retain large customers, longer sales cycles, increasing R&D spend just to stand still. The numbers lag the underlying reality by 12-24 months, so the leading indicators come from talking to former customers, sales people, and competitors, not from the 10-K.", category: "Analysis", difficulty: "Advanced" },
  { q: "If insider selling has accelerated meaningfully, what would make you ignore it as a signal?", a: "Most insider sales are scheduled 10b5-1 plans set up well in advance and don't reflect a real-time view; you can verify that by looking at filing notes. Tax-driven selling around year-end or option expirations also tends to be mechanical rather than informative. New executives often sell to diversify out of concentrated grants without a negative view on the business. The signal becomes meaningful when it's discretionary, large relative to the holder's remaining stake, and clustered across multiple executives in the same window. A CEO selling 50% of their position in a single open-market trade outside of a 10b5-1 plan is a much stronger signal than a scheduled monthly sale. Context matters more than the headline.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through duration versus convexity tradeoffs when positioning for a Fed pivot.", a: "If you expect a pivot, you want long duration to capture rate-driven price appreciation, but you also want convexity because if the pivot is larger or faster than priced, convex bonds gain disproportionately. The trap is that callable bonds and MBS have negative convexity, so when rates fall they get called or prepaid and you don't capture the upside. The cleanest expression is long-duration Treasuries or non-callable IG corporates with high convexity, paired potentially with a long-call structure on rates. The risk if you're wrong is large - duration cuts both ways. Position sizing depends on conviction in the pivot timing, not just the direction.", category: "Macro", difficulty: "Advanced" },
  { q: "If the 2s10s curve steepens 50bps but the 10s30s flattens 20bps, what does that imply about market expectations?", a: "The 2s10s steepening reflects expectations that the Fed will cut rates - front-end yields fall faster than back-end. The 10s30s flattening at the same time suggests the long end isn't moving up much, which means inflation expectations are anchored and term premium isn't widening. Combined, the market is pricing easing cycle without inflation re-anchoring, which is the bullish soft-landing scenario for risk assets. If 10s30s were also steepening, you'd be looking at inflation expectations rising and a less benign rate-cut path. The shape of the move matters as much as the direction.", category: "Macro", difficulty: "Advanced" },
  { q: "When would you take credit spread risk over duration risk, and vice versa?", a: "Take credit spread risk when spreads are wide relative to historical, default rates are at or near their cyclical peak, and the macro setup supports recovery - you're getting paid for risk that's diminishing. Take duration risk when yields are at cyclical highs, the central bank is at the end of its tightening cycle, and growth is decelerating - you're capturing rate-driven price appreciation. The combined trade is rates falling and spreads tightening simultaneously, which is the risk-on bond rally setup of post-recession recoveries. The mismatched trade is taking both at the same time when you're not sure which leg is the dominant driver; that's how you blow up if a credit cycle inflects against you.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through how you'd analyze a BBB-rated cyclical issuer trading at 250bps spread.", a: "First, compare 250bps against the BBB index and the issuer's historical range - if the index is at 150bps and the issuer at 250, there's a 100bps idiosyncratic spread to understand. Look at leverage trajectory: where will net debt to EBITDA be in 12 and 24 months under base, downside, and recession scenarios? BBB cyclicals get punished hard in downgrades because forced selling kicks in when they cross into high-yield, so the relevant question is downgrade migration probability, not just default risk. Check the covenant package and call structure; many BBB cyclicals have callable bonds where the call protects them from rate-driven price upside. The decision tree is whether the spread compensates for downgrade risk, not whether 250bps looks attractive in absolute terms.", category: "Macro", difficulty: "Advanced" },
  { q: "If breakevens widen 30bps in a week, what does that imply about the macro setup?", a: "Breakevens reflect the market's expected inflation rate over the relevant horizon. A 30bps widening in a week is a major signal - either inflation expectations are re-anchoring higher, oil and commodities have spiked, or the Fed reaction function is being repriced more dovishly. Combined with what's happening on the nominal curve, you can separate the drivers: if nominal yields rose by less than breakevens, real yields fell, which is a risk-on, inflationary signal. If breakevens widened from a flight-to-quality bid leaving real yields up, that's a different macro picture. Inflation breakevens are noisy in the short term but matter for cross-asset positioning.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through the monetary policy transmission mechanism into corporate credit spreads.", a: "Fed policy hits credit spreads through multiple channels. First, lower rates compress risk-free yields, pushing investors out the risk curve and tightening spreads through demand. Second, lower rates reduce corporate refinancing costs, improving credit metrics over time. Third, easier policy supports growth expectations, which lowers default probability across cyclical sectors. Fourth, asset purchases or facility programs directly buy credit, compressing spreads mechanically. The full transmission takes 12-18 months to work through earnings and balance sheets, but spreads usually move within days of policy shifts because expectations price in. The 2020 episode showed all four channels operating simultaneously; the 2022 reversal showed them all reversing.", category: "Macro", difficulty: "Advanced" },
  { q: "If real rates rise 100bps while nominal rates rise 80bps, what's actually happening?", a: "Real yields rising faster than nominal means inflation breakevens are falling - the market is pricing lower inflation. Combined with rising nominal yields, this is typically a hawkish Fed regime where tightening is winning the inflation battle but cost of capital is rising for everyone. Real yields rising 100bps is a major headwind for long-duration equities like high-multiple tech and unprofitable growth, because their valuation is most sensitive to the discount rate. Gold and TIPS underperform in this regime; cash and short-duration credit outperform. It's also a regime that tends to break leveraged structures because financing costs reset higher in real terms.", category: "Macro", difficulty: "Advanced" },
  { q: "When does an inverted yield curve fail as a recession indicator?", a: "The inversion-to-recession transmission has worked because it reflected market expectations of future rate cuts in response to weakness. It can fail when the inversion is driven by a unique supply-demand dynamic at the long end - pension demand for long bonds, regulatory buying, or QE distorting term premium - rather than by genuine economic pessimism. The 2022-2024 inversion was the deepest since the 1980s but the recession was delayed or muted, partly because of fiscal support keeping nominal GDP elevated. The signal also weakens when central bank balance sheets are large enough to compress term premiums independently of cycle position. The right read is that inversion raises recession probability but doesn't determine timing, and the broader context matters.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through how you'd position fixed income going into a recession.", a: "Extend duration ahead of recession - long Treasuries and long-duration IG benefit from the Fed cutting cycle that historically accompanies downturns. Reduce credit risk before defaults spike; the time to be long credit is during the depths of a recession, not entering one. Within credit, move up the quality stack to A and AA rated names, and avoid energy, commercial real estate, and cyclical industrials. Munis and agencies hold up better than corporates in stress because of their flight-to-quality profile. The mistake investors make is being long spread duration too early; you want to be early on rates duration and late on credit duration, in that order.", category: "Macro", difficulty: "Advanced" },
  { q: "If oil moves $20 lower per barrel, how does that ripple through credit spreads across sectors?", a: "Energy IG and HY spreads widen materially - energy is roughly 15% of the HY index by weight, and lower oil reduces cash flow and increases default probability for E&P names. Pipelines and midstream are insulated by long-term volume contracts. Airlines, chemicals, and consumer discretionary benefit from lower input costs, so their spreads tighten. Banks with energy lending exposure - particularly Houston-based and Permian-focused regional banks - see indirect spread widening through credit quality concerns. EM sovereign spreads diverge by exposure: Saudi Arabia and Russia widen, India and South Korea tighten. The 2014-2016 oil crash is the canonical playbook - energy HY spreads went from 400bps to over 1500bps before recovering.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through currency hedging considerations for a US-based investor holding 30% European equities.", a: "Unhedged equity exposure means you're long European companies and short USD/EUR FX, so currency moves can swamp equity returns over short horizons. Over long horizons, FX tends to mean-revert and the hedge often costs more than it adds, especially when hedging into higher-yielding currencies costs negative carry. The optimal hedge ratio depends on the correlation between local equity returns and FX moves - European equities have historically been positively correlated with EUR, so hedging amplifies returns rather than dampening them. Many institutional investors run partial hedges around 50% as a balance. For taxable investors, FX gains and losses also have different tax treatment from equity returns, which complicates the calculus.", category: "Macro", difficulty: "Advanced" },
  { q: "When does a carry trade unwind become systemic versus idiosyncratic?", a: "An idiosyncratic unwind is when a single trade with concentrated positioning gets stopped out - a hedge fund forced to liquidate JPY shorts when BOJ surprises hawkish. Systemic unwinds happen when leverage in similar trades is broad-based across the financial system, so the initial unwind triggers margin calls and forced selling across correlated positions. The August 2024 yen carry unwind was systemic because of the scale and the leverage embedded across multiple investor types. The diagnostic is positioning data - CFTC, BIS, prime broker reports - and the funding currency's role in broader risk-taking. The risk of a systemic event is highest when implied vol is low, positioning is one-sided, and the central bank is signaling change.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through how you'd analyze sovereign risk for an emerging market bond.", a: "Start with debt sustainability - debt-to-GDP, debt-to-revenue, and the path under reasonable growth and rate scenarios. Then external position: current account deficit, FX reserves, external debt as a share of total. Political risk drives both willingness and ability to pay; election cycles, institutional quality, and history of restructuring matter. Currency regime determines whether you're really taking sovereign risk or sovereign-plus-FX risk. Compare the yield against EMBI and peer sovereigns at the same rating to identify the idiosyncratic component. The biggest mistake is anchoring on yield without modeling the recovery rate under a restructuring scenario - Argentine bonds at 15% yield with implied default looked attractive until you priced 30% recovery.", category: "Macro", difficulty: "Advanced" },
  { q: "If high-yield spreads are at 350bps and investment grade is at 100bps, what does the ratio tell you about positioning?", a: "A 3.5x ratio is in line with long-term averages, suggesting credit markets are in middle-cycle territory - neither stressed nor euphoric. Historical compression below 2.5x has typically come at cycle peaks before defaults rise, like 2007 or 2021. Ratios above 5x signal recession risk being priced, like 2008 or March 2020. The ratio alone doesn't tell you whether spreads will widen or tighten next, but it tells you whether you're being paid enough to take incremental credit risk. The HY-IG ratio is also useful for relative value calls within fixed income; when it widens, IG looks expensive relative to HY, and vice versa.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through the difference between a hard landing and soft landing for portfolio positioning.", a: "A soft landing implies the Fed engineers inflation back to target without a recession - growth slows, unemployment ticks up modestly, and earnings hold. Equities outperform, credit spreads tighten, duration is mixed because rate cuts are gradual. A hard landing means growth contracts, unemployment rises sharply, earnings collapse, and credit defaults rise. Long duration outperforms, equities sell off, credit spreads widen materially before tightening as the Fed cuts. The positioning difference is risk-on versus risk-off; you don't straddle by being half-pregnant in both. The realistic answer is most investors should structure portfolios that survive a hard landing and benefit from a soft landing rather than betting one way.", category: "Macro", difficulty: "Advanced" },
  { q: "If the dollar strengthens 15%, how does that flow through multinationals in your portfolio?", a: "US-domiciled multinationals translate foreign earnings back into stronger dollars, so reported EPS gets hit by FX translation. The drag is most acute for companies with European, Latin American, or commodity-exporting country exposure. Hedging programs typically protect 12-18 months out but not beyond, so the second-year impact is larger than the first-year. Companies with USD-denominated debt and foreign cash flows - many EM corporates - face a compounding squeeze. Sector-wise, consumer staples and industrials feel translation impact more than tech, which often invoices in USD globally. The 2014-2016 dollar strength cut S&P EPS growth by roughly 5-7% in aggregate; magnitude matters.", category: "Macro", difficulty: "Advanced" },
  { q: "When are MBS attractive versus corporates on a risk-adjusted basis?", a: "MBS are attractive when prepayment risk is muted - homeowners aren't refinancing because rates aren't falling rapidly - and the basis to Treasuries is wide relative to historical. They're unattractive in a rapidly falling rate environment because of negative convexity; the bonds get called away at par while corporates capture the duration upside. Versus IG corporates, the trade-off is rate sensitivity versus credit sensitivity - MBS are pure rate plus prepayment, corporates are rate plus spread. When credit cycles look late and spreads are tight, MBS offer better risk-adjusted return because you're not taking idiosyncratic default risk. In recoveries with widening spreads tightening, corporates outperform on credit beta.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through how you'd respond to a liquidity crunch in IG credit markets.", a: "Step one is assessing whether your portfolio is liquidity-constrained - do you have redemptions or rebalancing needs that force selling at distressed levels. Step two is identifying which parts of the book to defend versus rotate; high-quality, deep-liquidity issues you hold to maturity, while lower-quality, smaller-issue exposures you might trim to fund opportunistic buying. Step three is recognizing that liquidity crunches create the best entry points for credit; March 2020 was a generational opportunity for investors who could lean in. Pre-arranged credit lines and tight communication with prime brokers matter operationally. The strategic mistake is treating the crunch as a credit event when it's actually a liquidity event - the wrong reaction is to sell when bid-ask is widest.", category: "Macro", difficulty: "Advanced" },
  { q: "If unemployment ticks up 50bps while wage growth stays at 4%, what's the Fed's likely response?", a: "The 50bps unemployment uptick is a labor market softening signal - maybe one or two more prints push the Fed toward cutting. But wage growth at 4% is above the 3-3.5% range consistent with 2% inflation, so the Fed has a tension. Historically, the Fed has reacted to unemployment first and worried about wages later, especially under a Powell-era dual mandate framework. The most likely response is gradual rate cuts paired with hawkish forward guidance to keep wage expectations anchored. The bond market would rally on the cuts; the equity market response depends on whether earnings hold up through the slowdown. The risk is the Fed cuts too aggressively and re-accelerates inflation, repeating 1970s mistakes.", category: "Macro", difficulty: "Advanced" },
  { q: "When does duration help in a rising rate environment, contrary to intuition?", a: "When the rate move is driven by a one-time repricing rather than a sustained tightening cycle, the initial price decline reverses as yields stabilize and reinvestment at higher rates compounds. Long-duration bonds held to maturity earn the higher yield even after the price hit. The other case is when curve flattening from short-end moves dominates the level move; the long end actually rallies on flight-to-quality even as the front rises. The 2025 setup has been an example - front-end repricing while long bonds rallied on growth concerns. The mental error is assuming rising rates uniformly hurt all duration; the curve dynamics matter as much as the level move.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through how you'd analyze the credit risk of a leveraged loan refinancing wall in 2027.", a: "Map the maturity profile by year, industry, and rating bucket - the maturity wall isn't uniform; it concentrates in B-rated and lower in 2027-2028 vintages issued in low-rate 2020-2021. Refinancing risk depends on the rate environment at maturity; if SOFR stays elevated, the new coupon is materially higher and many borrowers can't service the increased interest expense. The metric to track is interest coverage at current rates, particularly for floating-rate loans where rates have already reset. Private credit demand may absorb some of the wall, but middle-market deal flow can't substitute for institutional loan demand at scale. The 2027 wall coincides with private equity portfolio companies needing exits, so distress cycles in PE-owned credits could compound. Historical loan default cycles run 6-8% peak default rates; a similar cycle here would be material.", category: "Macro", difficulty: "Advanced" },
  { q: "If TIPS are pricing 2.5% inflation 5 years forward and the Fed targets 2%, what's the trade?", a: "The market is pricing 50bps above the Fed target, which means either the market doesn't believe the Fed will hit 2%, or there's a real-yield mispricing in the TIPS market. The trade depends on which view you take. If you believe the Fed will succeed, buy nominal Treasuries and sell TIPS - you collect the difference as breakevens narrow. If you believe inflation runs higher, buy TIPS or sell nominal Treasuries. Operationally, TIPS liquidity is lower than nominal Treasuries, so size matters. The trade has long been a low-conviction one because the breakeven spread reflects both inflation expectations and a varying inflation risk premium that's hard to estimate.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through how you'd think about commodity exposure as an inflation hedge.", a: "Commodities have historically been the best real-asset inflation hedge over multi-year horizons, but the correlation with inflation is not stable - it's strongest when inflation is supply-driven, weaker when demand-driven. The implementation matters: direct commodity exposure via futures faces roll yield drag in contango markets, equity exposure adds beta and operational leverage, and managed futures add timing and trend-following dynamics. Gold is a real-rate hedge more than an inflation hedge per se; it works when real rates fall, regardless of the inflation level. The 2021-2022 inflation episode showed broad commodity benchmarks performing well early then giving back gains as demand softened. The honest assessment is commodities are an asymmetric hedge with meaningful tracking error to spot inflation.", category: "Macro", difficulty: "Advanced" },
  { q: "When does fixed income offer equity-like returns, and what's the catch?", a: "After major rate sell-offs, fixed income offers yields high enough that total return over 3-5 year horizons can approach equity-like 7-9% nominal returns. The 2022-2023 setup created exactly this: IG corporates at 6%+ yields, HY at 9-10%, EM debt at 8%. The catch is twofold: first, you need rates to stop rising for the yield to translate into total return rather than further price depreciation; second, the credit cycle has to hold up so that spread tightening or just stable carry plays out. The other catch is path - you might earn 8% annualized over five years but with drawdowns that feel equity-like. Investors who saw the 2022 yield reset as a generational opportunity were partly right; investors who treated it as a guaranteed return path missed the mark on volatility.", category: "Macro", difficulty: "Advanced" },
  { q: "If credit spreads are tight but volatility is rising, what does that mismatch tell you?", a: "Tight spreads paired with rising vol is a classic late-cycle setup - credit markets are still being supported by demand for yield while equity markets are pricing growing economic uncertainty. The two markets are inconsistent, and the resolution usually comes through credit catching down rather than equities catching up. The 2007 setup looked similar: spreads compressed to multi-decade lows while VIX rose through the year before the credit shock arrived. The trade is to reduce credit risk into the divergence, not to bet on it persisting. Spreads can stay tight longer than fundamentals justify, but the asymmetry is poor: limited upside from further compression, large downside from widening.", category: "Macro", difficulty: "Advanced" },
  { q: "Walk me through the difference between momentum and trend-following in factor investing.", a: "Momentum is cross-sectional - it ranks securities within a universe and buys the top decile while shorting the bottom decile, exploiting relative performance persistence. Trend-following is time-series - it goes long an asset when its own price is above a moving average and short when it's below, exploiting absolute performance persistence. Cross-sectional momentum tends to work in equity factor portfolios with rebalancing every 1-12 months; time-series trend dominates in macro and CTA strategies. Both rely on the same behavioral phenomenon of slow information diffusion, but the implementation, capacity, and crash risk profiles are different. Momentum has spectacular drawdowns at reversal points; trend has lower drawdowns but underperforms in choppy markets.", category: "Markets", difficulty: "Advanced" },
  { q: "If a long-short equity strategy delivers 5% with 8% volatility, but its beta is 0.3, what's the actual alpha?", a: "Alpha is the excess return over what the beta exposure should have delivered. With beta 0.3 and assuming a 7% market return, the beta contribution is roughly 2.1%, leaving 2.9% as alpha. The Sharpe of the alpha portion is what matters for assessing manager skill; you can replicate the beta cheaply through index funds. The 5% headline number is misleading if you don't decompose it - the manager might be charging hedge fund fees for what's predominantly market exposure with a partial short overlay. The right diligence question is what the alpha looks like adjusted for fees and gross exposure, not what the absolute return looks like.", category: "Markets", difficulty: "Advanced" },
  { q: "When does mean reversion fail catastrophically as a strategy?", a: "Mean reversion fails when the underlying process changes regime and what looked like an extreme deviation was actually the start of a new trend. The classic example is selling vol after a vol spike under the assumption that vol mean-reverts; if a true crisis follows, the strategy gets blown out. Pair trades between historically correlated assets fail when the spread widens through historical bounds because of a structural break - LTCM blew up partly because their convergence trades didn't converge. Mean reversion works in stationary regimes; it kills you in regime shifts. The risk management discipline is hard stops, position sizing relative to the historical range, and reducing exposure when the spread approaches multi-decade extremes.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you'd interpret a 90-day rolling correlation between two stocks dropping from 0.7 to 0.2.", a: "The correlation breakdown could mean fundamental divergence - the two businesses are no longer driven by the same underlying factors - or it could be transitory noise from idiosyncratic events. Look at what changed in the 90-day window: did one company report a major event, change strategy, or move to a different growth trajectory? If the correlation breakdown is fundamental, your historical hedge ratio or pair trade is broken and needs to be re-evaluated. If it's transitory, the correlation will likely revert. The bigger lesson is that rolling correlations are noisy and traders who size off them can be whipsawed; long-term factor exposure matters more than short-term realized correlation.", category: "Markets", difficulty: "Advanced" },
  { q: "If your scenario analysis shows a -15% portfolio drawdown in a stagflation scenario, how do you act on that?", a: "First, decide whether the scenario is severe enough to justify pre-positioning. A 15% drawdown over a multi-year stagflation period isn't catastrophic for a long-term investor and might not warrant rebuilding the book. If the scenario is plausible but not your base case, you might tilt at the margin - reducing high-multiple growth exposure, adding real assets and commodities, extending into hard-asset equities. If you're convicted, you'd rebuild more aggressively but accept the cost of being wrong if stagflation doesn't materialize. The discipline is matching the size of the pre-positioning to the probability times the impact, not just the impact. Scenario analysis is a tool for sensitivity, not a forecast.", category: "Markets", difficulty: "Advanced" },
  { q: "When is value-at-risk most misleading?", a: "VaR is most misleading during regime shifts because it's calculated from historical data that doesn't include the new regime's risks. It also misses tail risk by construction - 95% VaR tells you nothing about the worst 5% of outcomes. VaR is mark-to-market sensitive, which means illiquid assets like private equity show artificially low VaR because their prices don't fluctuate daily. Hedge funds in 2007-2008 had VaR breach their internal limits multiple standard deviations beyond historical assumptions because the joint distribution of asset returns shifted. The right complements are stress testing, expected shortfall (CVaR), and scenario analysis grounded in actual historical episodes, not statistical assumptions.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you'd compute a probability-weighted expected return for an event-driven trade.", a: "Identify the possible outcomes - deal closes, deal breaks, deal terms renegotiated - and assign each a probability and a price impact. Multiply through and sum: expected return equals the sum of probability times outcome. The discipline is being honest about probabilities; merger arb traders often anchor on historical close rates without adjusting for current regulatory or financing conditions. The expected return then needs to be discounted for time to closing and risk-adjusted for the downside scenario's volatility. The trap is treating one outcome as 90% likely when the historical base rate is closer to 75% for similar deal structures. Position sizing follows expected return divided by downside, not expected return alone.", category: "Markets", difficulty: "Advanced" },
  { q: "If a strategy has a Sharpe of 1.5 but skew of -3, would you take it? Why?", a: "Negative skew of -3 is severe - it means the strategy has many small gains and rare large losses, typical of insurance-selling strategies like short vol, picking up pennies in front of a steamroller. The Sharpe looks attractive but understates true tail risk because Sharpe assumes Gaussian returns. The right framework is to ask if the embedded losses, when they arrive, would be tolerable from a business or career perspective. A 1.5 Sharpe with -3 skew might be perfect for a structured product issuer with offsetting flows but disastrous for a discretionary fund where investors would redeem after the tail event. The decision depends on tolerance for path dependency, not just headline risk-adjusted returns.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you'd identify a regime shift in real time.", a: "Regime shifts are hard to detect in real time because they look like noise until they're confirmed. The signals I watch are correlation breakdowns across asset classes, volatility regime changes - a sustained vol level shift, not just spikes - and central bank reaction function changes. Multi-asset cross-correlation matrices flipping from negative to positive between stocks and bonds, as happened in 2022, is a major signal. Macro variables like inflation breakevens, term premium estimates, and credit spread term structures also flag regime shifts before equity markets recognize them. The honest answer is most participants identify regimes 6-12 months after they've started, which is fine if you're rebalancing slowly but disastrous if you're levered.", category: "Markets", difficulty: "Advanced" },
  { q: "When does volatility clustering matter for portfolio construction?", a: "Volatility clustering means high-vol days follow high-vol days - the GARCH effect documented since the 1980s. It matters for portfolio construction because constant-volatility-target strategies need to de-lever during clusters, which can be procyclical and amplify drawdowns if everyone is doing the same thing. It also matters for option pricing - implied vol can persist at elevated levels well after the initial shock, providing carry for vol sellers but only if you size for survival through the cluster. For long-only investors, volatility clustering means that immediate post-crash rebalancing back to target weights tends to outperform delayed rebalancing, because you're buying when forced sellers are still active.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through what factor crowding looks like and how to detect it before it unwinds.", a: "Factor crowding shows up as elevated cross-sectional correlation among hedge funds, narrowing dispersion between top and bottom decile holdings, and rising borrow costs for short legs. Position concentration in 13F data and short interest at multi-year highs are observable signals. The unwind catalyst is often unrelated to fundamentals - a single fund forced to liquidate triggers a cascade. The August 2007 quant crisis was the cleanest example; momentum and value factors both crashed simultaneously despite being uncorrelated in theory. Detecting crowding requires monitoring positioning data, not just price action. The defensive response is reducing factor exposure when crowding metrics flash, even if your fundamental thesis is unchanged.", category: "Markets", difficulty: "Advanced" },
  { q: "If a backtest shows 20% annualized returns over 10 years, what are the three traps you'd interrogate first?", a: "Survivorship bias is first: was the universe defined as stocks that exist today rather than the actual investable universe at each point in time? Look-ahead bias second: did the backtest use information not available at the time of trading, like restated fundamentals or revised analyst estimates? Overfitting third: how many parameters were tuned, and would the strategy survive on a hold-out sample or in walk-forward testing? Beyond these three, transaction costs and market impact are usually understated. A clean 20% backtest after fees, on a realistic universe, with realistic transaction costs is genuinely rare; most that show up that way have one of these flaws. The white test in practice is whether the strategy worked on data after the backtest was constructed.", category: "Markets", difficulty: "Advanced" },
  { q: "How does survivorship bias distort the perceived performance of hedge funds?", a: "Industry index returns systematically overstate true performance because failed funds drop out of the database while survivors remain. Studies estimate the bias adds 200-400bps to reported industry returns versus the actual experience of investors who held the average fund. The bias is worst in strategies with high tail risk - macro, distressed, long-short - where blowups remove the worst performers. It also affects manager selection: investors looking at top-decile historical performers are selecting from a survivor pool, and forward returns mean-revert toward the broader population. The correct way to evaluate hedge fund returns is to use survivorship-free databases or to apply a haircut to reported figures. Most allocators significantly overestimate hedge fund net-of-fee returns.", category: "Markets", difficulty: "Advanced" },
  { q: "When does signal decay matter most, and how do you protect against it?", a: "Signal decay matters most when the strategy is publicly known - academic factor papers, popular sell-side reports, or strategies that have been around for decades. Once enough capital pursues a signal, it gets arbitraged away or the risk premium it harvests shrinks. Protection against decay involves continuously refreshing the signal pool, mixing slow-moving and fast-moving signals so the portfolio isn't dependent on any single source, and monitoring out-of-sample performance versus backtest expectations. If realized return is materially below backtest, the signal is decaying. The deeper protection is investing in proprietary data sources, alternative information, or qualitative judgment that's harder to replicate at scale.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you'd evaluate two managers, one with 12% returns and 15% volatility versus one with 8% returns and 6% volatility.", a: "First, compute Sharpe ratios assuming a 4% risk-free rate - the first manager is at 0.53, the second at 0.67. The second has better risk-adjusted returns despite lower headline returns. But you need to look beyond Sharpe: drawdown profiles, downside deviation, and skew matter for understanding what each looks like in stress. The 15% vol manager might have smoother gains and rare large losses or might have consistent left-tail exposure. Match the manager to the mandate - if you're funding a liability with a 6% return target, the second manager is a better fit; if you need 10%+ to meet an absolute return goal, the first is unavoidable. Risk-adjusted comparison alone doesn't tell you which is right for the portfolio.", category: "Markets", difficulty: "Advanced" },
  { q: "If correlations across asset classes spike to 0.9 in a stress event, what does that mean for diversification logic?", a: "Correlation convergence in stress means realized diversification is far less than expected, and many portfolios show drawdowns that violate their VaR assumptions. The phenomenon is well-documented - 2008, March 2020, and 2022 all saw equity, credit, and even traditional safe havens move together. The implication is that diversification logic based on historical correlations is most fragile precisely when you need it most. Practical responses include reserving genuine safe-haven allocations to long Treasuries and cash for crisis periods, sizing portfolios for stress correlations rather than average correlations, and recognizing that tail-risk hedges are the only true diversifiers in extreme events. The mental model shift is from expected diversification to conditional diversification.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through the difference between alpha and beta decomposition for a long-only equity fund.", a: "Beta is the portion of returns explained by exposure to the market or to known factor risks - size, value, momentum, quality, low-vol. Run a regression of fund returns against the relevant benchmark and factors to isolate the systematic exposure. Alpha is the intercept and the residual return that the factor model can't explain - true manager skill. A fund showing 10% returns with 8% from factor beta and 2% from alpha is largely a factor portfolio. Investors should pay factor-level fees for the beta and active fees only for the demonstrated alpha. The challenge is alpha is statistically noisy over short periods, so you need long samples to distinguish skill from luck.", category: "Markets", difficulty: "Advanced" },
  { q: "When does a low-volatility factor underperform, and why?", a: "Low-vol underperforms in strong momentum-driven bull markets where high-vol names lead the rally, because low-vol portfolios are structurally underweight the most volatile and often highest-returning growth names. It also underperforms in late-cycle environments where defensive sectors get expensive and the premium for low-vol compresses. The 2017-2021 period was tough for low-vol because growth dominated. Mechanically, low-vol works through capturing the risk anomaly that high-vol stocks underperform their CAPM-implied returns, but that anomaly is regime-dependent and the spread can stay tight for years. The factor is best held as part of a multi-factor allocation, not as standalone exposure.", category: "Markets", difficulty: "Advanced" },
  { q: "If your stress test assumes 2008-like correlations, what blind spot remains?", a: "2008 was a credit-led crisis with specific transmission channels through banks, securitization markets, and money market funds. The blind spot is that future crises will have different transmission mechanisms - pandemic-driven economic shutdown like 2020, rates-led repricing like 2022, or AI/data-center concentration risks that haven't surfaced yet. Calibrating to 2008 misses idiosyncratic vulnerabilities of the current portfolio that didn't exist in 2008. It also assumes central bank responses will mirror 2008-2009, which depends on inflation context. The deeper issue is that all backward-looking stress tests miss the true tail risk that hasn't been observed yet. Multiple historical scenarios plus forward-looking imagined scenarios is better than calibration to a single historical event.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you'd handle a multi-factor model where the factors are increasingly correlated.", a: "Increasing factor correlation typically means the factors are converging on similar economic drivers - value, quality, and low-vol all tilting toward stable mature businesses in a particular cycle position. Mathematically, your factor model loses explanatory power because the factors are no longer independent risk sources. The practical response is either to reweight toward less-correlated factors, decompose what's actually driving the correlation, or accept that the implied diversification of multi-factor allocation has degraded. You can also rotate to factor combinations whose correlations are historically stable, like momentum plus quality. The risk is treating the model as if it still produces independent exposures when in fact you've concentrated risk into one underlying driver.", category: "Markets", difficulty: "Advanced" },
  { q: "If implied vol is 25% but realized vol over the last 30 days is 12%, what does that tell you about positioning?", a: "Implied minus realized is the variance risk premium, and 13 points of premium is wide but not unusual at certain points in the cycle. It could reflect dealer hedging demand, expected upcoming events, or risk premium for tail uncertainty. If realized stays low for the period the implied is priced over, vol sellers earn the spread; if a shock arrives and realized spikes, vol sellers get hurt. The trade depends on whether you have a view on realized - is there a catalyst window or are markets in a stable regime? Short vol with poor risk management is a classic blow-up strategy because the carry is positive until it isn't. Sizing has to assume the realized number could converge violently.", category: "Markets", difficulty: "Advanced" },
  { q: "When does a beta of 1.2 actually understate true risk?", a: "Beta is a backward-looking, linear measure that assumes the relationship between the stock and the market is stable. It understates risk when the company has hidden leverage that hasn't been tested in a drawdown, when the business model is sensitive to a specific regime not present in the calibration window, or when there's a discrete event risk not reflected in historical price movement. A 1.2 beta tech stock that has never been through a rates-up environment understates true rates sensitivity. Similarly, beta misses concentration risk - a 1.2 beta company with a single key customer is much riskier than a 1.2 beta diversified company. Convexity, gap risk, and asymmetric payoffs aren't captured by linear beta.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you'd construct a stress scenario you haven't seen historically.", a: "Start with the macro story: what would have to be true for the scenario to play out - what drives growth, inflation, central bank response, currency, and credit channels. Then translate to asset-level moves: equity multiples, earnings revisions, credit spread widening, term premium shifts. Calibrate magnitudes by analog - pick a historical episode with similar drivers and scale based on differences in starting conditions. For example, stagflation stress would scale from 1970s episodes but adjust for today's debt levels, central bank reaction function, and energy mix. Then run the portfolio through and identify which positions break. The output isn't a forecast - it's a map of where vulnerabilities sit and which hedges would actually work.", category: "Markets", difficulty: "Advanced" },
  { q: "If a factor has worked for 20 years and stops working for 2, do you keep believing in it? What evidence would change your mind?", a: "20 years of evidence is meaningful but the question is whether the underlying economic rationale still holds. Two years of underperformance is normal sampling variance for most factors, but I'd investigate whether the structural condition supporting the factor has changed. For value, the question is whether the relative pricing inefficiency between cheap and expensive stocks has been arbitraged away or whether the spread has just compressed temporarily. Evidence that would change my mind: structural changes in how stocks are valued (longer-duration cash flows due to lower rates), changes in market participant composition, or evidence that the factor's mechanism has been replicated by AI-driven strategies at scale. I'd keep believing but reduce conviction, not abandon it after 24 months.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you'd think about position sizing using a Kelly framework with realistic adjustments.", a: "Full Kelly sizing is mathematically optimal for log-wealth maximization but in practice nearly always too aggressive - it assumes you know edge and odds precisely, which you don't. Most practitioners size at quarter-Kelly to half-Kelly to account for parameter uncertainty and drawdown tolerance. The framework forces you to be explicit about expected return, expected loss, and probability of each, which is useful discipline even if the numbers are estimates. The realistic adjustment includes correlation across positions - Kelly on a single trade doesn't account for the rest of your book - and capacity constraints on the trade itself. Position sizing is one of the most underappreciated drivers of long-term performance, but Kelly is a starting framework, not a literal rule.", category: "Markets", difficulty: "Advanced" },
  { q: "Walk me through how you build a differentiated investment thesis.", a: "Start by mapping consensus - what is sell-side modeling, what is the buy-side implicitly pricing through the multiple. Then identify a specific assumption that consensus has wrong and explain why you have insight others lack. The differentiation has to come from somewhere: proprietary data, primary research, framework variance, or a longer time horizon. A thesis that says the company will grow faster than expected without specifying which assumption is wrong is not differentiated. The test is whether you can articulate the bull case in one sentence and the variant perception in one sentence - both sharp, both contestable, both falsifiable.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "When do channel checks add real value, and when are they noise?", a: "Channel checks add value when the channel reveals information that's truly leading - real-time demand, pricing dynamics, competitive intensity, customer satisfaction - that won't show up in financials for one or two quarters. They're noise when the sample is too small, when the contacts have their own agendas, or when you're checking on something already widely known. Quality matters more than quantity - five high-signal conversations with former employees of the customer base beats twenty surface-level retailer chats. The other risk is confirmation bias: analysts hear what they want to hear and weight the calls that match their thesis. Channel checks should challenge the thesis, not validate it.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you read an earnings call critically versus passively.", a: "Passive reading captures the prepared remarks and the headline numbers. Critical reading focuses on the Q&A section, where unscripted moments reveal management's actual confidence level, what they're avoiding, and what's unsettling them. Tonal shifts, hedged language, and the questions they don't answer crisply are signals. I track changes in language quarter over quarter - strong becomes solid, on track becomes monitoring, confident disappears entirely. Compare what was said versus what was guided last quarter; companies often pre-announce trouble through subtle language before formally cutting guidance. The transcript is data; the body language reflected in it is intel.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "If consensus estimates have been revised up four quarters in a row, what's your reaction?", a: "Sustained positive revisions historically have predicted continued outperformance - the post-earnings drift phenomenon. But four quarters is also a setup risk: expectations are now elevated, beats become harder, and a single miss can re-rate the stock sharply lower. The right question is whether the underlying business is genuinely accelerating or whether estimates were just too low entering the period. Look at revision magnitude versus the surprise the company is generating - if revisions lag actual delivery, more upside; if revisions are catching up to actual, the cycle is mature. Crowded long positioning at the end of a revision cycle is one of the most asymmetric setups against you.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd assess management credibility over multiple earnings cycles.", a: "Track every public commitment - revenue targets, margin expectations, capital allocation plans - and compare what they said to what they delivered. Score them across a multi-year window, weighting more recent cycles more heavily. The best CEOs underpromise and overdeliver, with realistic guidance that converts into actual results. Red flags include consistent annual targets that slip into the next year, ranges that are revised down quarterly, or sudden capital allocation pivots that contradict prior commitments. Credible management teams also own their mistakes publicly, which builds long-term trust even when results are bad. Credibility, once lost, takes 3-5 years to rebuild and often requires leadership change.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "When is conservative guidance actually a bearish signal?", a: "When the conservatism is materially below what was previously communicated and there's no explanation for the recalibration, that's a warning. Companies that move from expect to outperform language to in line with conservative consensus are often signaling internal weakness before formally cutting. The other case is when management has been historically aggressive and suddenly turns conservative - the inflection often precedes a guidance cut. Truly conservative companies set guides that beat consistently for 8-12 quarters; if a conservative company starts barely meeting their own guide, the safety margin is shrinking. The lesson is to read guidance relative to historical patterns of conservatism, not as standalone signals.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd identify a crowded trade and why crowding isn't always a sell signal.", a: "Signs of crowding include sustained outperformance versus fundamentals, elevated short interest among low-quality competitors, hedge fund 13F overlap concentration, and sell-side coverage initiations on the long side. Sentiment indicators - option positioning, retail flows, fund manager surveys - also flag positioning extremes. Crowding alone doesn't trigger an unwind; what matters is the absence of marginal buyers and the presence of forced sellers. A crowded but fundamentally improving stock can keep working. The signal flips dangerous when crowding combines with deteriorating fundamentals or when a known catalyst risk materializes. Selling crowded longs that are still delivering is one of the most costly career moves; the harder discipline is sizing down at the margin while staying long.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "If you're building a short thesis, what's the bar relative to a long thesis?", a: "The bar is much higher because shorts are asymmetric - your upside is capped at 100% (the stock going to zero), your downside is unlimited, and you fight beta drag plus carry costs. A short thesis needs a specific catalyst with a defined timeline, evidence the market is structurally wrong rather than just temporarily euphoric, and a thesis robust enough to survive ranges of macro outcomes. Borrow costs and squeeze risk constrain position sizing. The best shorts combine deteriorating fundamentals with a balance sheet trigger, like covenant violation, refinancing wall, or accounting irregularity. Pure valuation shorts on quality companies are a notoriously bad way to lose money.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd present a 5-bagger long idea to a skeptical investment committee.", a: "Lead with the variant perception in a sentence: the market is pricing this as X; I believe it's Y because of Z. Then layer the business overview briefly - skeptical PMs don't want a tutorial. Spend most of the time on the thesis: what changes, when, and how do we get paid. Address the bear case head-on and explain why the most obvious objections are wrong. Show the math: base case, downside, upside, expected value, position sizing. End with what would change your mind. The biggest mistake is structuring the pitch like a sell-side report; the committee wants compressed insight, not narrative.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "When does monitoring become micromanaging, and how do you tell?", a: "Monitoring is checking whether the thesis is on track at the cadence the thesis requires - a multi-year compounder needs quarterly checks, an event-driven trade needs weekly. Micromanaging is reacting to every news item, every analyst report, every price move regardless of whether it changes the underlying thesis. The tell is whether your sells are thesis-driven or noise-driven; if you can map every exit to a specific change in the underlying story, monitoring is working. If you're trimming on a hot day and adding on a cold day without a fundamental anchor, you're micromanaging your way to mediocre returns. The discipline is to write down the thesis-break conditions at entry and check against them, not at price.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd know it's time to exit a position you still believe in.", a: "There are three legitimate exit triggers even when you still believe in the thesis. First, the upside has been substantially realized and the risk-reward is no longer asymmetric. Second, a better opportunity is available with similar conviction and higher expected return. Third, the position has grown to a size that creates portfolio risk independent of the thesis. The illegitimate trigger is fatigue - the thesis has played out longer than expected and you're tired of waiting, so you exit at the worst time. The discipline is to revalue the position from scratch as if you were initiating today and ask whether you'd buy at current levels. If yes, hold; if no, exit even if you still believe.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "If a stock you own is down 20% on news, how do you distinguish thesis break from noise?", a: "Pull the original investment write-up and identify which thesis pillars are affected. A 20% move on a transient miss - weather, FX, one-time customer issue - is noise; a 20% move on a strategic pivot, accounting irregularity, or fundamental demand deterioration is potentially a break. Talk to channel contacts and industry peers within 48 hours to validate or refute the bearish narrative. Resist the urge to either average down immediately or exit immediately - both reactions miss the analysis step. The right response is to update the model with the new information and ask if you'd buy at the new price knowing what you now know. If yes, add or hold; if no, exit and learn.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you compare sell-side research quality across firms.", a: "Differentiation in sell-side quality comes from access to management, depth of industry contacts, modeling precision, and predictive value of recommendations. I rank analysts on actual estimate revision accuracy versus reported results, the prescience of rating changes, and the quality of the underlying business analysis - not the brand of the firm. Bulge brackets have access; boutiques often have depth. The best analysts have multi-decade coverage of the same names and have built compounding relationships with management. The worst analysts mirror consensus and use sell-side templates. Tracking a five-year record of model accuracy gives you a real signal on who to trust.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "What behavioral biases are you most prone to as an investor?", a: "Honesty here matters more than the specific bias. For me, the trap is confirmation bias - once I've committed capital, I weight new information that supports the position more heavily than information that contradicts it. The discipline is to actively seek disconfirming evidence and have a thesis-break checklist written at entry. Anchoring on entry price is another trap - I'm not selling until I get back to my cost basis is a setup for catastrophic losses. Recency bias matters too; recent volatility shapes risk perception more than long-term averages should. Self-awareness about these biases is the prerequisite to managing them; pretending you're rational is the most dangerous bias of all.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through a post-mortem on a bad investment.", a: "First, distinguish whether the loss came from a bad process or a bad outcome - you can have a sound process and still lose, or a bad process that won money by accident. Bad outcomes from sound process are tolerable; bad processes need fixing. Decompose the loss: was the thesis wrong, was the timing wrong, was the position sizing wrong, did you miss a key risk that was knowable. Document what you learned and which heuristics need updating. The post-mortem should produce specific behavioral changes, not just sympathy for yourself. The investors who compound longest do exhaustive post-mortems on losses and barely review wins.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "When does I was right but early actually mean you were wrong?", a: "When the path losses were so large you got stopped out, your fund got pulled, or you couldn't add to the position when the thesis finally played out. Being right and unprofitable is the same as being wrong from an investment perspective. The famous Keynes line that markets can stay irrational longer than you can stay solvent is the warning. Early is also often a cover story for being wrong on the actual timing mechanism - you didn't understand what would force the repricing, so you sized as if it was imminent when it wasn't. The discipline is to be clearer about what catalyst makes you right and to size positions around that catalyst's distribution, not around the eventual rightness of the thesis.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd interrogate your own thesis 6 months in.", a: "Pull the original write-up and treat it as if a new analyst wrote it - what assumptions need updating, what data is now available that wasn't, what has the company actually delivered. Check whether the price reaction has been consistent with the thesis playing out or whether you're being saved by macro tailwinds. Identify which thesis pillars are confirmed, which are uncertain, and which are weakened. The honest review usually surfaces one or two assumptions that need revising even when the overall thesis is intact. Set a quarterly cadence for this review with specific questions written down - drift happens when reviews become performative rather than rigorous.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "If you and another analyst on your team strongly disagree on a name, how do you resolve it?", a: "First, identify the specific point of disagreement - it's almost never the entire thesis but rather a specific assumption like growth rate, multiple, or margin trajectory. Then debate the disagreement on the merits with evidence; emotional anchoring or seniority shouldn't drive the resolution. Sometimes the team takes a smaller position reflecting reduced conviction, sometimes the senior PM makes the call, sometimes you agree to disagree and one of you owns the position. The healthiest culture treats disagreement as productive - a unanimous team is often a groupthink team. The unhealthiest is one where junior analysts can't openly challenge senior PMs; that's how funds end up holding losers longer than they should.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd build conviction on a name when management is uncooperative.", a: "Talk to ex-employees, customers, suppliers, competitors, and industry analysts who don't depend on management access for their living. Trade publications, court filings, regulatory documents, and patents can reveal more than IR meetings. Insider transaction filings tell you what management thinks about valuation when they're trading their own money. Competitor 10-Ks often reveal what's happening in the focal company's segment more honestly than the focal company's own filings. Sometimes the lack of management access is itself information - what are they hiding, why don't they want investors close. Conviction without management access is possible; sometimes more honest, since you're not anchored on their narrative.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "When do you trust the bear case more than the bull case, and why?", a: "Bears are often closer to the truth because shorts have to think about all the ways something can go wrong, while longs can rationalize bad outcomes as buying opportunities. Bear cases that hold up to investigation and identify specific, falsifiable problems - accounting issues, customer concentration, competitive threats - deserve serious weight. Bull cases that consist mostly of TAM expansion stories and optimistic margin assumptions are weaker. I particularly trust bear cases from short sellers who have skin in the game and have been right before, like Carson Block on Sino-Forest or Jim Chanos on Enron. The skepticism premium is structurally underpriced in market commentary.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd think about adding to a losing position versus cutting it.", a: "Adding only makes sense if the thesis is intact or stronger and the price decline has improved the risk-reward materially. Cutting makes sense if the thesis is weakening, the loss has reduced your conviction, or your portfolio risk needs rebalancing. The wrong mental model is averaging down to lower cost basis - your cost basis is irrelevant to forward returns. The right framework is to evaluate the position from scratch at the current price as if you were initiating. Many great investors have rules against averaging down on positions where the original thesis isn't strengthening; the gambler's fallacy applies to investing too.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "If a sell-side analyst publishes an upgrade with a thesis identical to yours, does that worry you?", a: "It depends on where the stock has run. If the upgrade comes early in the thesis playing out, the sell-side validation can attract incremental capital and help the stock work faster - not necessarily a worry. If the upgrade comes after meaningful outperformance and the buy-side is already long, you might be late in the cycle and the sell-side is catching up. The other consideration is dilution of your edge: if sell-side has caught up to your view, the consensus has shifted and your variant perception is gone. Track upgrades-to-rating ratio across the coverage; when the entire sell-side has buys, you're in mature crowded territory.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you keep your investment process honest over time.", a: "Document every decision at the time it's made - why you bought, what you expect, what would change your mind. Review every position quarterly against the original thesis. Run annual reviews of process versus outcomes to separate skill from luck. Have peers who can challenge you and won't just rubber-stamp your views. Track win rate, average gain, and average loss separately to understand whether your edge is in selection, sizing, or holding period. The deepest discipline is fighting the post-hoc narrative - it's easy to remember you always thought a stock would work after it has; honest records prevent that revisionism.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "When is being contrarian actually being stubborn?", a: "Contrarian thinking is valuable when the consensus is wrong for identifiable reasons - structural blind spots, narrative anchoring, or systematic mispricing. Stubbornness is holding a contrarian view after the underlying evidence has shifted against you. The test is whether new information would change your mind; if you can't articulate what would, you're not investing, you're believing. Contrarians who compound - Buffett on equities in 1974, Tepper in 2009 - update their views aggressively when evidence arrives. Stubborn contrarians double down when wrong and call it conviction. The line is thin and the only protection is ruthless honesty about what you actually know versus what you want to believe.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "Walk me through how you'd think about your investment edge in a market where everyone has data.", a: "Data access has been commoditized - every fund has Bloomberg, alternative data feeds, satellite imagery, transaction panels. The edge has shifted from information to interpretation and from speed to judgment. Behavioral edge persists because human nature doesn't change - patience, willingness to be wrong publicly, long-horizon thinking are scarcer than they sound. Process edge - how rigorously you research, how you size, how you handle drawdowns - still matters. Network edge from industry experts, former operators, and people who've seen multiple cycles is hard to replicate. The genuinely durable edges are temperamental and structural, not informational. Funds that compete on information edge in 2026 face an arms race they can't win.", category: "Stock Pitch", difficulty: "Advanced" },
  { q: "If you had 48 hours to learn a new industry, walk me through your process.", a: "Start with two or three 10-Ks from the largest players to learn the business model, key drivers, and competitive dynamics in management's own words. Then read one investor day deck per major player for forward-looking commentary. Hour 8-16 goes to industry-specific KPIs: what metrics matter, how the unit economics work, who the customers and suppliers are. Then read sell-side initiations from two or three firms - differing views are more useful than one. Spend hour 24-36 talking to a former operator or industry expert via an expert network or LinkedIn outreach. The last block synthesizes: what would have to be true for the bull case, what would have to be true for the bear case, where is the variant perception possible.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through the KPIs you'd track for a SaaS business versus a payments business.", a: "SaaS focuses on ARR growth, net revenue retention (>110% is healthy), gross retention (>90% is healthy), CAC payback (<24 months), magic number (>1.0), and Rule of 40 (growth plus FCF margin >40%). Payments focuses on TPV (total payment volume) growth, take rate, volume mix by merchant size and category, processing costs as percent of revenue, and unit economics per merchant cohort. SaaS is a subscription business with predictable revenue and reinvestment; payments is a transaction business with cyclical volume tied to consumer spending. The valuation frameworks differ accordingly - SaaS gets revenue or ARR multiples, payments gets P/E or EV/EBITDA. Confusing the two is a common mistake by generalists.", category: "Analysis", difficulty: "Advanced" },
  { q: "When does a cyclical look like a secular and vice versa?", a: "A cyclical looks secular when it's mid-cycle and growth has compounded for several years without obvious headwinds - shipping companies in 2020-2021, US homebuilders in 2005, semiconductors in 2017. The narrative becomes this time is different precisely at the peak. A secular looks cyclical when an external shock disrupts the growth trajectory - software during the 2022 budget freeze, e-commerce during 2022 reopening. Most cyclicals get expensive at the peak and cheap at the trough; most seculars trade at premium multiples that compress only during cyclical shocks. The test is whether the demand driver depends on macro conditions or on an autonomous structural shift; the answer takes years of data to confirm.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how network effects compound and how they decay.", a: "Network effects compound when each new user makes the product more valuable to existing users, creating a feedback loop - classic examples are payment networks (more merchants attract more users, attracting more merchants), social platforms, and marketplaces. The compounding rate depends on the strength of the network - two-sided networks compound faster than one-sided, dense networks faster than sparse. Decay happens when the network gets so large that quality dilutes, when alternative networks emerge with better matching algorithms, or when the underlying use case becomes commoditized. Facebook's network effect compounded through 2015 and started decaying as TikTok and Instagram cannibalized engagement among younger demographics. The decay is often invisible in revenue for years after engagement has peaked, which makes the inflection hard to time.", category: "Analysis", difficulty: "Advanced" },
  { q: "If you're valuing a copper miner, walk me through your framework.", a: "Start with reserves and mine life - a 20-year reserve base earns a different multiple than a 5-year base because the option value of higher prices over time differs. Then estimate normalized cash flow at a mid-cycle copper price, not spot, because peak earnings at peak copper are unsustainable. Cost position matters enormously - first-quartile producers earn through cycles while fourth-quartile producers go bust at the bottom. Project pipeline and capex requirements determine what FCF is actually available to shareholders after sustaining the resource base. Then layer on country risk and political stability - a Chilean mine has different risk than a Peruvian or Congolese mine. Multiples for miners cluster around 5-8x mid-cycle EBITDA; the variance comes from cost position and reserve life.", category: "Analysis", difficulty: "Advanced" },
  { q: "What metrics matter most for a P&C insurer versus a regional bank?", a: "P&C insurers are evaluated on combined ratio (under 100 means underwriting profit), investment yield on the float, and reserve adequacy. The business is essentially using policyholder money to invest; profitability comes from both underwriting and investment income. Regional banks are evaluated on net interest margin, efficiency ratio, loan growth, credit quality (non-performing loans, allowance for loan losses), and ROTCE. Different liability structures, different risk dynamics, different sensitivity to rates. P&C is rate-sensitive on the investment side; banks are rate-sensitive on both assets and liabilities. The capital frameworks differ - Basel III for banks, statutory accounting for insurers - and the regulatory regimes diverge.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through SaaS cohort analysis and what 110% net revenue retention actually implies.", a: "Cohort analysis tracks groups of customers who started in the same time period through their spending journey. NRR of 110% means the average dollar of revenue from a cohort grows 10% per year through upsell and cross-sell, net of churn. 110% is healthy but the components matter: is it 5% churn offset by 15% expansion, or 0% churn and 10% expansion? Expansion-driven NRR is more durable than churn-suppressed NRR. Cohort vintage analysis reveals whether newer cohorts retain better or worse than older ones - improving cohorts is a strong signal, deteriorating cohorts mean the customer acquisition machine is bringing in lower-quality customers. The compound math is powerful: 110% NRR for 10 years means a cohort doubles, which is why mature SaaS businesses have huge installed-base monetization optionality.", category: "Analysis", difficulty: "Advanced" },
  { q: "If a semiconductor company is at the peak of its cycle, how would you know?", a: "Lead times have stretched to 30-50+ weeks, customers are double-booking orders, capacity utilization is at or above 90%, and capex has been ramping for 6-12 quarters. Inventory at the customer level is elevated, distributors are sitting on stock, and the gross margin trajectory has peaked or rolled over. The narrative shifts from shortage to normalization to destocking in roughly three quarter increments. The 2017-2018 NAND cycle, the 2021-2022 logic cycle, and prior cycles all followed similar shapes. The peak is visible 6-9 months after it happens, which is why pure cycle calls in semis are hard; what works is reading the leading indicators - lead times normalizing, capex stopping, distributor inventory days climbing - rather than the lagging revenue line.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how reimbursement risk affects healthcare names.", a: "Reimbursement is the price the payer pays for a service or product - Medicare, Medicaid, commercial insurers, or international single-payer systems. Reimbursement changes can be regulatory (CMS rate-setting decisions), commercial (PBM contract negotiations), or political (drug pricing legislation). A drug that gets 50% of revenue from US commercial markets faces different reimbursement risk than one focused on Medicare. The structural pressures are downward - payers consolidate, value-based contracting expands, and price transparency legislation accelerates. Med-tech and diagnostics face similar but distinct risks through CMS coverage decisions and CPT code reimbursement. The 2017 340B drug pricing changes and the 2022 IRA Medicare negotiation provisions are recent examples of how reimbursement can re-rate entire subsectors.", category: "Analysis", difficulty: "Advanced" },
  { q: "When does a consumer discretionary name benefit from a recession?", a: "Counter-cyclical consumer discretionary exists when the brand benefits from trade-down dynamics or stay-at-home substitution. Dollar stores and discount retailers gain wallet share from higher-income households trading down. Off-price retailers benefit from inventory imbalances at full-price retailers. Auto parts retailers benefit when consumers defer new vehicle purchases and maintain older vehicles longer. Within categories, premium brands with strong loyalty hold up better than mid-tier brands; mass and luxury hold up better than middle. The 2008-2009 recession showed dollar stores and off-price thriving while specialty apparel and casual dining suffered. The framework is to identify substitution dynamics rather than assume all consumer discretionary moves together.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd analyze an industrial with high fixed costs going into a downturn.", a: "High fixed cost businesses have severe operating leverage - small revenue declines drive large earnings declines because the cost base doesn't flex. Look at decremental margins from prior cycles; a business that loses 40% of incremental dollars on the way down will see EPS implode in a recession. Balance sheet matters more than usual: can the company fund the trough without dilutive equity raises or covenant violations? Look at the customer base's own cycle position - building products companies tied to housing have a long tail; aerospace OEMs have multi-year backlogs that cushion. The opportunity in industrials with high fixed costs is they have outsized operating leverage in the recovery, which is when you want to own them; the risk is they have to survive the trough first.", category: "Analysis", difficulty: "Advanced" },
  { q: "If oil moves from $75 to $50, who in energy wins and who loses?", a: "E&P producers with high break-evens lose materially - shale producers in the Bakken or Eagle Ford with $50+ all-in costs struggle while Permian operators at $40 break-evens are more resilient. Refiners can benefit from the wider crack spread if their input costs fall faster than gasoline prices. Pipeline and midstream companies are mostly volume-contracted with stable cash flows; they're insulated. Energy service companies get hit hard because capex compresses across the producer base. Integrated oil majors are mixed - upstream pain offset by downstream gain. Within E&P, balance sheet leverage and hedge book quality determine survivors. The 2014-2016 oil crash showed all these dynamics; smaller, leveraged shale producers went bankrupt while majors and pipelines weathered it.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through airline economics and why margins are structurally thin.", a: "Airlines have high fixed costs (aircraft, gates, crews), high variable costs tied to fuel, and pricing that's bounded by competition since the product is largely commoditized for leisure travelers. Capacity additions tend to outpace demand because every airline thinks it can grow profitably, and adding marginal seats erodes industry pricing. Network economics create some moat for hub-based carriers, but low-cost carriers continually pressure them. Loyalty programs and credit card economics are increasingly the highest-margin part of the business. Buffett's famous critique that airlines have destroyed cumulative capital was accurate through the 1980s-2000s; consolidation post-2008 improved economics, but the 2020 COVID shock reminded investors that the business model is fragile to demand shocks. Margins of 5-10% are typical at peak and negative at trough.", category: "Analysis", difficulty: "Advanced" },
  { q: "When does telecom capex pay off and when does it destroy capital?", a: "Telecom capex pays off when the technology cycle creates differentiated services that earn pricing power - the 4G LTE buildout in 2010-2014 enabled mobile data that customers paid premium prices for. It destroys capital when the buildout creates more capacity than demand can absorb at acceptable prices, or when competing operators race to build the same network in the same geography. The 5G buildout has been mixed - real technical capabilities deployed but limited applications that drive consumer ARPU expansion. Fiber to the home is generally returnable if the household economics are right but destroys capital in overbuilt markets. The framework is whether the capex enables new revenue streams or just maintains the existing competitive position; pure capacity additions in mature markets are usually capital destructive.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd think about Amazon's disruption risk to a traditional retailer.", a: "Start with the product category - Amazon has commoditized search, transparency, and convenience for SKU-level shopping but has limited advantage in experiential retail, fashion that requires fitting, or fresh food categories. Traditional retailers that have moved to omnichannel with strong digital infrastructure compete better than pure brick-and-mortar legacy players. The right question isn't whether Amazon competes but whether the retailer's specific positioning is defensible against ecommerce price transparency and shipping convenience. Costco competes well because membership economics and treasure-hunt curation differ from Amazon; Bed Bath & Beyond competed poorly because they had no differentiated value beyond category breadth. The framework is to look at the specific competitive moat in the retailer's segment rather than assume Amazon disrupts all retail equally.", category: "Analysis", difficulty: "Advanced" },
  { q: "If a SaaS company's net revenue retention drops from 120% to 105%, what's likely going on?", a: "The 15-point compression is severe and signals one of three things. First, customers may be cutting back on seat counts or downsizing tiers, common in macro slowdowns where enterprise IT budgets get scrutinized. Second, expansion velocity may be slowing because the product has saturated within existing accounts. Third, competition may have increased, with customers consolidating onto fewer vendors. Look at the components: gross retention dropping signals churn problems, expansion compressing signals upsell problems. The 2022-2023 SaaS reset showed many companies dropping from 130%+ NRR to sub-110%, mostly through customer downsizing rather than churn. A drop to 105% with sub-90% gross retention is much worse than 105% with 95% gross retention; the structure of the decline matters.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through bank ROE drivers and what differentiates the best banks from average.", a: "ROE decomposes into net interest margin times asset turnover times leverage, adjusted for credit costs. The best banks combine premium NIM through deposit franchise quality (low-cost funding via sticky retail deposits) with disciplined credit underwriting (lower charge-offs through cycles) and operational efficiency (lower cost-to-income ratio). JPMorgan and Bank of America have benefited from scale economics and digital efficiency, while community banks compete on relationship banking and underwriting quality. The differentiation is rarely about being the most aggressive - it's about being the most disciplined through cycles. Banks that grew fastest in 2005-2007 lost the most in 2008-2009; banks that grew steadily over 2010-2020 compounded book value through the cycle.", category: "Analysis", difficulty: "Advanced" },
  { q: "If you're looking at a vertical software company, what do you focus on that doesn't matter for horizontal SaaS?", a: "Vertical SaaS has narrower TAM, so penetration rate within the target vertical matters far more than total TAM expansion. The depth of workflow integration creates higher switching costs than horizontal tools - once a vertical SaaS company is embedded in the daily operations of an industry, replacing it requires re-training and re-integration. Industry-specific compliance and data requirements (HIPAA in healthcare, FINRA in financial services) create barriers to entry that horizontal SaaS doesn't have. The other consideration is industry cycle exposure - a vertical SaaS company serving restaurants is exposed to restaurant industry cycles in ways that horizontal CRM isn't. Multiples for high-quality vertical SaaS have historically been higher than horizontal at comparable growth because of the durability premium.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how AI changes the moat of legacy enterprise software.", a: "Legacy enterprise software derived moats from data lock-in, integration depth, and switching costs. AI threatens the user experience layer - if a customer can rebuild a thin AI-driven interface on top of their data, the legacy vendor becomes just a database. But the data itself, the integrations, and the workflow institutionalization remain hard to replicate quickly. The winners will be incumbents who layer AI capabilities into their existing products (Microsoft Copilot, Salesforce Einstein) versus pure-play AI startups that lack the data and distribution. The losers are companies whose value proposition was UI/UX without underlying defensibility. The current debate around Microsoft's Copilot adoption and ROI is the canonical example of how this plays out in real time. The threat is real but the timing and magnitude vary widely by vertical and customer type.", category: "Analysis", difficulty: "Advanced" },
  { q: "When is a healthcare biotech's clinical trial readout already priced in?", a: "Sell-side consensus probability of success, options market positioning, and short interest all give signals. If the implied probability of success in the stock price exceeds 75% but the actual trial design suggests a 50/50 outcome, the stock has front-run the science. Options markets are often more efficient than equity - event implied volatility and skew tell you what the market is pricing for tail outcomes. Insider transactions in the months before the readout also provide intel. The asymmetry is brutal: stocks that have run into a readout and miss can drop 60-80%; stocks that beat already-elevated expectations sometimes don't move much. The trade for fundamental investors is rarely the readout itself; it's positioning around the reaction or longer-term commercial uptake.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd analyze a chemicals company with commodity inputs and specialty outputs.", a: "The business has two distinct profit drivers: spread economics on the commodity-to-specialty transformation and volume economics in the end markets. Look at the historical spread - is it stable, cyclical, or compressed by new entrants? Specialty chemicals with proprietary formulations earn through-cycle margins of 15-25%; commodity chemicals earn 5-15% with much higher volatility. End markets matter - a specialty chemical sold into automotive faces different cyclicality than one sold into healthcare or food. R&D intensity and patent runway determine how long the specialty premium lasts. The valuation should be a blend of specialty multiples (15-20x EBITDA) on the differentiated portion and commodity multiples (6-10x) on the undifferentiated portion. Conglomerate chemicals companies often trade at SOTP discounts because the market struggles to value the mix correctly.", category: "Analysis", difficulty: "Advanced" },
  { q: "If a regional bank's NIM expanded 30bps but loan growth is flat, what's actually happening?", a: "NIM expanding without loan growth typically reflects asset repricing in a rising rate environment - floating-rate loans reset higher and the bank earns more on the same balance sheet. Deposit beta is the offset; if deposits are repricing slower than loans, NIM benefits. Flat loan growth suggests either demand weakness, underwriting tightening, or competitive intensity at the lower end. The combination can be a yellow flag: NIM peaking on rates while business volumes don't grow indicates a stagnant business riding short-term tailwinds. The next phase is usually deposit repricing catching up or competitors growing market share, both of which compress NIM. Look at non-interest income trends and credit quality to triangulate the underlying health of the franchise.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd assess a consumer staples company facing private label encroachment.", a: "Private label gains share in categories where brand differentiation is weak and consumers can't easily distinguish quality - paper goods, basic groceries, some over-the-counter health products. Categories with strong emotional or quality differentiation (premium spirits, baby care, pet food) resist private label longer. The pricing structure matters: leading brands often command 30-50% premiums; private label closes the gap to 10-20% over time as quality improves and consumer trust builds. Margin compression for branded players comes first through promotional spend, then through actual price cuts, then through volume loss. Companies with strong brand portfolios and innovation pipelines can defend; companies with stagnant brands eventually see private label win the category. The Reckitt versus generic story across multiple categories has been the modern playbook.", category: "Analysis", difficulty: "Advanced" },
  { q: "When does heavy infrastructure capex justify a higher multiple versus signal capital destruction?", a: "It justifies a higher multiple when the capex builds asset-light competitive advantage - data center capacity that generates predictable lease revenue, fiber networks that create regulatory moats, or vertically integrated supply chains that lock in cost advantages. It signals capital destruction when the capex is defensive - maintaining capacity in commoditized markets, racing to match competitor builds, or expanding into geographies without differentiation. The test is incremental returns: does the next dollar of capex earn 15%+ ROIC, or 5%? Telecom in 2000-2002 destroyed massive capital on infrastructure that nobody could monetize. Hyperscaler capex in 2010-2020 created durable competitive moats. The difference was demand visibility and competitive structure, not the gross investment number.", category: "Analysis", difficulty: "Advanced" },
  { q: "Walk me through how you'd build the bear case on a quality compounder with 40% market share.", a: "Start with where growth comes from - at 40% share, organic growth requires either category expansion or share gains from increasingly entrenched competitors. Regulatory risk often emerges at dominant share levels (antitrust scrutiny, structural separation). New entrants with adjacent technology can be more disruptive than competitors with similar tech - Netflix to cable, Tesla to legacy auto, Amazon to retail. Margin defense becomes harder as the company has fewer expansion levers and more public scrutiny. Management capital allocation often deteriorates at high share levels - dominant companies start buying questionable acquisitions because they can't reinvest organically. The variant perception bear case is usually market share is high enough that the next decade looks fundamentally different from the last. Quality compounders at peak share are still where the most disappointing 5-year returns hide.", category: "Analysis", difficulty: "Advanced" },
];
